(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,115529,e=>{"use strict";var i=e.i(843476),t=e.i(271645),r=e.i(618566),a=e.i(935524),n=e.i(508776),o=e.i(127464),s=e.i(218129);let d={ar:{"token-generator":{title:"مُولِّد رموز عشوائية آمنة",description:"أنشئ رموزًا عشوائية آمنة تشفيريًا بطول قابل للتخصيص (1–512 حرفًا) ومجموعات أحرف متنوعة (أحرف كبيرة، أحرف صغيرة، أرقام، رموز). مثالي لمفاتيح API ومعرفات الجلسات وكلمات المرور وأي احتياجات للرموز الآمنة."},"hash-text":{title:"مُولِّد تجزئة النصوص",description:"أنشئ تجزئات آمنة من النصوص أو الملفات باستخدام خوارزميات MD5 وSHA1 وSHA256 وSHA224 وSHA512 وSHA384 وSHA3 وRIPEMD160. مثالي لفحوصات سلامة البيانات وتجزئة كلمات المرور."},bcrypt:{title:"مُولِّد تجزئة كلمات المرور bcrypt",description:"أنشئ تجزئات Bcrypt آمنة لكلمات المرور مع معامل تكلفة قابل للتعديل. مثالي لتخزين كلمات المرور بأمان في التطبيقات."},"uuids-generator":{title:"مُولِّد UUID",description:"أنشئ معرفات UUID بجميع الإصدارات: NIL (أصفار بالكامل)، v1 (قائم على الوقت)، v3 (قائم على الاسم بـ MD5)، v4 (عشوائي)، v5 (قائم على الاسم بـ SHA-1). يدعم الإنشاء بالجملة (حتى 50) ونطاقات أسماء مخصصة للإصدارين v3/v5."},"ulid-generator":{title:"مُولِّد ULID",description:"أنشئ معرفات فريدة عالميًا قابلة للترتيب معجميًا (ULID). بديل لمعرفات UUID رتيب التزايد وقابل للترتيب الزمني وآمن للاستخدام في URL."},"encrypt-decrypt-text":{title:"أداة تشفير النصوص وفك تشفيرها",description:"شفّر وفك تشفير النصوص باستخدام خوارزميات تشفير متماثل (AES وغيرها) مع مفاتيح وأوضاع مخصصة. معالجة آمنة بالكامل على جهاز العميل."},"bip39-passphrase-generator":{title:"مُولِّد عبارة BIP39 التذكيرية",description:"أنشئ عبارات BIP39 استذكارية آمنة (12–24 كلمة) لمحافظ العملات المشفرة مع إمكانية اختيار قوة الإنتروبيا."},"hmac-generator":{title:"مُولِّد HMAC",description:"احسب HMAC (رمز مصادقة الرسائل القائم على التجزئة) باستخدام خوارزميات تجزئة ومفاتيح سرية متنوعة لضمان سلامة الرسائل والمصادقة عليها."},"rsa-key-pair-generator":{title:"مُولِّد زوج مفاتيح RSA",description:"أنشئ أزواج مفاتيح RSA عامة/خاصة بطول بتات قابل للاختيار (2048، 4096، وغيرها) للتشفير والتوقيع وSSH."},"password-strength-analyzer":{title:"محلل قوة كلمة المرور",description:"حلّل قوة كلمات المرور في الوقت الفعلي: الإنتروبيا، تقدير وقت الكسر، اكتشاف الأنماط الشائعة، وفحوصات الاختراقات."},"qr-code":{title:"مُولِّد رمز QR للروابط والنصوص",description:"أنشئ رموز QR قابلة للتخصيص من عناوين URL أو النصوص أو رسائل البريد الإلكتروني أو بطاقات vCard. نزّلها بتنسيقات متعددة مع تصحيح الأخطاء وإضافة الشعارات."},"wifi-qr-code":{title:"مُولِّد رمز QR للواي فاي",description:"أنشئ رموز QR قابلة للمسح لشبكات WiFi. يدعم WPA/WPA2 وWEP والشبكات بدون كلمة مرور وأسماء SSID المخفية وإعدادات WPA2-EAP للمؤسسات، مع ألوان مخصصة وتنزيل فوري."},barcode:{title:"مُولِّد الباركود",description:"أنشئ باركودات قابلة للتخصيص بتنسيقات متعددة (CODE128 وEAN13 وUPC وCODE39 والمزيد). اضبط عرض الشريط والارتفاع والألوان والهوامش وموضع النص والخط والتنسيق. معاينة فورية مع نسخ إلى الحافظة وتنزيل PNG."},"contact-qr-code":{title:"مُولِّد رمز QR لجهة اتصال vCard",description:"أنشئ رموز QR احترافية تحتوي على معلومات الاتصال الكاملة الخاصة بك (بتنسيق vCard). أضف الاسم والهاتف والبريد الإلكتروني والمسمى الوظيفي والموقع الإلكتروني والعنوان والمزيد. مثالي لبطاقات العمل والتواصل المهني والمشاركة الرقمية."},"qr-code-reader":{title:"قارئ ومفكِّك رموز QR والباركود",description:"امسح وفك تشفير رموز QR والباركودات أحادية وثنائية الأبعاد فورًا من الصور أو الملفات المرفوعة أو كاميرا الويب. استخرج عناوين URL والنصوص ومعلومات الاتصال وبيانات اعتماد Wi-Fi ومعلومات المنتجات والمزيد بنتائج فورية."},"json-yaml":{title:"محوِّل JSON إلى YAML عبر الإنترنت",description:"حوّل بسلاسة بين JSON وYAML في الاتجاهين مع تحقق وتنسيق فوريين. مثالي للمطورين الذين يتعاملون مع ملفات الإعداد وتبادل البيانات."},"date-time":{title:"محوِّل تنسيق التاريخ والوقت",description:"حوّل التواريخ والطوابع الزمنية بين تنسيقات متنوعة، بما في ذلك طوابع Unix الزمنية وسلاسل ISO والأنماط المخصصة. مثالي لتصحيح الأخطاء وتكاملات API."},"number-base":{title:"محوِّل أساس الأعداد",description:"حوّل الأرقام بسرعة بين الأنظمة الثنائية والسداسية العشرية والعشرية والثمانية. يدعم الأرقام الكبيرة والحسابات الفورية للمبرمجين والمهندسين."},"cron-parser":{title:"مُحلِّل تعبير cron",description:"حلّل تعبيرات cron إلى أوصاف واضحة مقروءة للبشر. يدعم الثواني والاختصارات (@daily و@hourly وغيرها) والوضع المفصّل وتنسيق 24 ساعة وشروحات تفصيلية للرموز لجدولة المهام."},html:{title:"مُرمِّز ومفكِّك كيانات HTML",description:"رمّز أو فك ترميز الأحرف الخاصة إلى كيانات HTML لمنع ثغرات XSS أو لعرض النصوص المنسقة بأمان في محتوى الويب."},url:{title:"مُرمِّز ومفكِّك URL",description:"رمّز عناوين URL بالترميز النسبي المئوي لنقلها بأمان أو فك ترميزها مرة أخرى إلى نص مقروء. أساسي لتطوير الويب والتعامل مع معاملات API."},base64:{title:"مُرمِّز ومفكِّك Base64 عبر الإنترنت",description:"رمّز البيانات الثنائية أو النصوص إلى Base64 لمرفقات البريد الإلكتروني وواجهات API، أو فك ترميزها بسهولة مع تحقق مدمج."},jwt:{title:"مفكِّك ومُفتِّش رموز JWT",description:"فك ترميز رموز JSON Web Token لفحص الترويسات والحمولات والتواقيع دون مفاتيح سرية. ممتاز لتصحيح أخطاء تدفقات المصادقة."},json:{title:"مُنسِّق ومُدقِّق JSON",description:"جمّل وصغّر وتحقق من بيانات JSON في الوقت الفعلي. اكتشف الأخطاء وتأكد من صحة بنية JSON لتكامل سلس."},xml:{title:"مُنسِّق وطابع XML المنسَّق",description:"نسّق مستندات XML لسهولة القراءة، واطوِ العناصر المتداخلة، وتحقق من صحة البنية. مفيد لإعدادات XML وتبادل البيانات."},sql:{title:"مُنسِّق ومُجمِّل SQL",description:"نسّق وجمّل وأزِح استعلامات SQL لتحسين قابلية القراءة. يدعم صياغة SQL القياسية مع إزاحة قابلة للتخصيص وكلمات مفتاحية بأحرف كبيرة وفواصل أسطر."},"lorem-ipsum":{title:"مُولِّد نص Lorem Ipsum",description:"أنشئ نصوصًا بديلة قابلة للتخصيص باللاتينية أو لغات أخرى. حدّد عدد الفقرات أو الكلمات أو الجمل لنماذج التصميم والنماذج الأولية."},checksum:{title:"حاسبة المجموع الاختباري للملفات",description:"احسب المجاميع الاختبارية للملفات أو النصوص للتحقق من السلامة. يدعم CRC32 وMD5 وSHA1 وSHA256 وSHA384 وSHA512 للتنزيلات والنسخ الاحتياطية."},"inspector-case-converter":{title:"أداة فحص النصوص وتحويل حالة الأحرف",description:"حلّل إحصائيات النصوص مثل عدد الكلمات وتكرار الأحرف، مع التحويل بين camelCase وsnake_case وPascalCase والمزيد لشيفرة نظيفة."},regex:{title:"أداة اختبار وتصحيح التعبيرات النمطية",description:"اختبر التعبيرات النمطية وصحّح أخطاءها مع مطابقة مباشرة واستبدال وتمييز للصياغة. يدعم الأعلام ومجموعات الالتقاط للتحقق الدقيق من الأنماط."},"text-diff":{title:"أداة فحص ومقارنة الفروق النصية",description:"قارن نصين جنبًا إلى جنب أو ضمن السطر مع اختلافات مرمّزة بالألوان. مثالي لاكتشاف التغييرات في الشيفرة أو الإعدادات أو السجلات أو المستندات بدقة على مستوى الكلمات والأحرف."},"multi-language-translator":{title:"مترجم JSON متعدد اللغات",description:"ترجم الكلمات والعبارات إلى أكثر من 11 لغة فورًا. أنشئ ملفات common.json جاهزة للاستخدام لتطبيقك (i18n) بتنسيق camelCase أو snake_case أو أي تنسيق آخر."},"markdown-editor":{title:"محرر ومعاين Markdown المباشر",description:"اكتب وحرّر وعاين Markdown في الوقت الفعلي مع تمييز للصياغة وعرض مباشر ودعم الوضع الداكن/الفاتح وخيارات التصدير. مثالي للملاحظات وملفات README والتوثيق ومنشورات المدونات."},"icon-generator":{title:"مُولِّد أيقونات تطبيقات بالذكاء الاصطناعي لنظامي iOS وAndroid",description:"أنشئ مجموعات أيقونات تطبيقات كاملة لأنظمة iOS وAndroid من صورة مصدر واحدة. إزالة الخلفية بالذكاء الاصطناعي لأيقونات شفافة، أدوات تدوير وقلب، قوالب أنماط عصرية (Rounded وSquircle وCircle)، رفع من URL أو لصق من الحافظة، مقاييس مخصصة لتصدير ملفات PNG/JPEG فردية، اختيار لون الخلفية لـ JPEG، وتغيير حجم وضغط بجودة عالية."},"image-converter":{title:"مُحسِّن ومحوِّل الصور وصانع PDF",description:"محول صور متقدم يدعم التنسيقات الحديثة: AVIF وWebP وJPEG XL ‏(JXL) وMozJPEG وPNG وGIF المتحرك. تحكم كامل في الجودة وتغيير الحجم والتحسين والمعالجة الدفعية والتحويل بين التنسيقات ودمج الصور في ملف PDF واحد (PNG وJPG/JPEG وGIF وWebP فقط)."},"pdf-to-images":{title:"محوِّل PDF إلى صور",description:"استخرج صورًا عالية الجودة من ملفات PDF صفحة بصفحة. اختر الإخراج PNG أو JPEG، واضبط الدقة (72–288 DPI) وجودة JPEG، وعالج عدة ملفات PDF دفعة واحدة، وعاين الصفحات، ونزّلها فرديًا أو كملف ZIP."},"ip-geolocation":{title:"البحث عن الموقع الجغرافي لعنوان IP",description:"استرجع فورًا بيانات الموقع الجغرافي لأي عنوان IP (أو عنوان IP الحالي). تشمل المدينة والمنطقة والدولة والمنطقة الزمنية وISP وخط العرض/الطول والمزيد. يمكن تصدير النتائج بتنسيقات متعددة (JSON وXML وYAML وغيرها)."}},zh:{"token-generator":{title:"安全随机令牌生成器",description:"生成加密安全的随机令牌，可自定义长度（1–512个字符）和字符集（大写、小写、数字、符号）。适用于API密钥、会话ID、密码或任何安全令牌需求。"},"hash-text":{title:"文本哈希生成器",description:"使用MD5、SHA1、SHA256、SHA224、SHA512、SHA384、SHA3和RIPEMD160算法从文本或文件生成安全哈希。适用于数据完整性校验和密码哈希。"},bcrypt:{title:"Bcrypt 密码哈希生成器",description:"为密码生成安全的Bcrypt哈希，成本因子可调。非常适合应用程序中的安全密码存储。"},"uuids-generator":{title:"UUID 生成器",description:"生成所有版本的UUID：NIL（全零）、v1（基于时间）、v3（基于名称MD5）、v4（随机）、v5（基于名称SHA-1）。支持批量生成（最多50个）以及v3/v5的自定义命名空间。"},"ulid-generator":{title:"ULID 生成器",description:"生成ULID（可按字典序排序的全局唯一标识符）。单调递增、可按时间排序、URL安全，是UUID的理想替代。"},"encrypt-decrypt-text":{title:"文本加密与解密工具",description:"使用对称算法（AES等）以自定义密钥和模式加密和解密文本。安全的客户端处理。"},"bip39-passphrase-generator":{title:"BIP39 助记词短语生成器",description:"为加密货币钱包生成安全的BIP39助记词（12–24个单词），熵强度可选。"},"hmac-generator":{title:"HMAC 生成器",description:"使用多种哈希算法和密钥计算HMAC（基于哈希的消息认证码），用于消息完整性和身份验证。"},"rsa-key-pair-generator":{title:"RSA 密钥对生成器",description:"生成RSA公钥/私钥对，位长可选（2048、4096等），用于加密、签名和SSH。"},"password-strength-analyzer":{title:"密码强度分析器",description:"实时分析密码强度：熵值、破解时间估算、常见模式检测和泄露检查。"},"qr-code":{title:"URL 和文本二维码生成器",description:"从URL、文本、电子邮件或vCard创建可自定义的二维码。支持纠错和logo叠加，可以多种格式下载。"},"wifi-qr-code":{title:"WiFi 二维码生成器",description:"为WiFi网络生成可扫描的二维码。支持WPA/WPA2、WEP、无密码、隐藏SSID和企业级WPA2-EAP配置，可自定义颜色并即时下载。"},barcode:{title:"条形码生成器",description:"生成多种格式的可自定义条形码（CODE128、EAN13、UPC、CODE39等）。可调整条宽、高度、颜色、边距、文字位置、字体和样式。实时预览，支持复制到剪贴板和PNG下载。"},"contact-qr-code":{title:"vCard 联系人二维码生成器",description:"生成包含完整联系信息的专业二维码（vCard格式）。包括姓名、电话、电子邮件、职位、网站、地址等。非常适合名片、社交和数字分享。"},"qr-code-reader":{title:"二维码与条形码读取/解码器",description:"从图片、上传文件或摄像头即时扫描和解码二维码及1D/2D条形码。实时提取URL、文本、联系信息、Wi-Fi凭据、产品信息等。"},"json-yaml":{title:"在线 JSON 转 YAML 转换器",description:"无缝地在JSON和YAML之间互相转换，支持即时验证和格式化。非常适合处理配置文件和数据交换的开发者。"},"date-time":{title:"日期与时间格式转换器",description:"在多种格式之间转换日期和时间戳，包括Unix时间戳、ISO字符串和自定义模式。适用于调试和API集成。"},"number-base":{title:"数字进制转换器",description:"在二进制、十六进制、十进制和八进制之间快速转换数字。支持大数字和实时计算，面向程序员和工程师。"},"cron-parser":{title:"Cron 表达式解析器",description:"将cron表达式解析为清晰易懂的描述。支持秒、宏（@daily、@hourly等）、详细模式、24小时制以及任务调度符号的详细说明。"},html:{title:"HTML 实体编码与解码器",description:"将特殊字符编码或解码为HTML实体，以防止XSS漏洞或在网页内容中安全地呈现格式化文本。"},url:{title:"URL 编码与解码器",description:"使用百分号编码对URL进行编码以便安全传输，或将其解码回可读文本。是Web开发和API参数处理的必备工具。"},base64:{title:"在线 Base64 编码与解码器",description:"将二进制数据或文本编码为Base64，用于电子邮件附件和API，或借助内置验证轻松解码。"},jwt:{title:"JWT 令牌解码与检查器",description:"解码JSON Web Token以检查头部、载荷和签名，无需密钥。非常适合调试身份验证流程。"},json:{title:"JSON 格式化与校验器",description:"实时美化、压缩和验证JSON数据。检测错误，确保JSON语法正确，实现无缝集成。"},xml:{title:"XML 格式化与美化工具",description:"格式化XML文档以提高可读性，折叠嵌套元素并验证结构。适用于XML配置和数据交换。"},sql:{title:"SQL 格式化与美化器",description:"格式化、美化和缩进SQL查询以提高可读性。支持标准SQL语法，可自定义缩进、关键字大写和换行。"},"lorem-ipsum":{title:"Lorem Ipsum 占位文本生成器",description:"生成拉丁语或其他语言的可自定义占位文本。可指定段落、单词或句子数量，用于设计稿和原型制作。"},checksum:{title:"文件校验和计算器",description:"计算文件或文本的校验和以验证完整性。支持CRC32、MD5、SHA1、SHA256、SHA384和SHA512，适用于下载和备份。"},"inspector-case-converter":{title:"文本检查器与大小写转换工具",description:"分析文本统计信息（如字数和字符频率），同时在camelCase、snake_case、PascalCase等格式之间转换，让代码更整洁。"},regex:{title:"正则表达式测试与调试器",description:"通过实时匹配、替换和语法高亮测试和调试正则表达式。支持标志和捕获组，实现精确的模式验证。"},"text-diff":{title:"文本差异检查与对比器",description:"并排或行内对比两段文本，差异用颜色标注。非常适合以单词和字符级精度发现代码、配置、日志或文档中的变化。"},"multi-language-translator":{title:"多语言 JSON 翻译器",description:"即时将单词和短语翻译成11种以上语言。为您的应用生成即用型common.json文件（i18n），支持camelCase、snake_case或任意格式。"},"markdown-editor":{title:"实时 Markdown 编辑与预览器",description:"实时编写、编辑和预览Markdown，支持语法高亮、实时渲染、深色/浅色模式和导出选项。非常适合笔记、README、文档和博客文章。"},"icon-generator":{title:"iOS 与 Android 的 AI 应用图标生成器",description:"从一张源图片生成iOS和Android的完整应用图标集。AI驱动的背景移除生成透明图标，旋转和翻转工具，现代风格模板（圆角、超椭圆、圆形），支持从URL上传或剪贴板粘贴，单张PNG/JPEG导出自定义比例，JPEG可选背景色，高质量缩放与压缩。"},"image-converter":{title:"图像优化、转换与 PDF 制作工具",description:"支持现代格式的高级图片转换器：AVIF、WebP、JPEG XL（JXL）、MozJPEG、PNG和动态GIF。全面控制质量、调整大小、优化、批量处理、跨格式转换，以及将图片合并为单个PDF（仅限PNG、JPG/JPEG、GIF、WebP）。"},"pdf-to-images":{title:"PDF 转图像转换器",description:"从PDF文件中逐页提取高质量图片。可选择PNG或JPEG输出，调整分辨率（72–288 DPI）和JPEG质量，批量处理多个PDF，预览页面，单独下载或打包为ZIP。"},"ip-geolocation":{title:"IP 地址地理位置查询",description:"即时获取任何IP地址（或您当前IP）的地理位置数据。包括城市、地区、国家、时区、ISP、经纬度等。结果可导出为多种格式（JSON、XML、YAML等）。"}},es:{"token-generator":{title:"Generador de tokens aleatorios seguros",description:"Genera tokens aleatorios criptográficamente seguros con longitud personalizable (1–512 caracteres) y conjuntos de caracteres (mayúsculas, minúsculas, números, símbolos). Ideal para claves de API, identificadores de sesión, contraseñas o cualquier necesidad de tokens seguros."},"hash-text":{title:"Generador de hash de texto",description:"Genera hashes seguros a partir de texto o archivos usando los algoritmos MD5, SHA1, SHA256, SHA224, SHA512, SHA384, SHA3 y RIPEMD160. Ideal para verificar la integridad de datos y el hash de contraseñas."},bcrypt:{title:"Generador de hash de contraseñas bcrypt",description:"Genera hashes Bcrypt seguros para contraseñas con factor de costo ajustable. Perfecto para almacenar contraseñas de forma segura en aplicaciones."},"uuids-generator":{title:"Generador de UUID",description:"Genera UUID de todas las versiones: NIL (todo ceros), v1 (basado en tiempo), v3 (basado en nombre con MD5), v4 (aleatorio), v5 (basado en nombre con SHA-1). Admite generación masiva (hasta 50) y espacios de nombres personalizados para v3/v5."},"ulid-generator":{title:"Generador de ULID",description:"Genera identificadores ULID (Universally Unique Lexicographically Sortable Identifier). Una alternativa a los UUID que es monotónica, ordenable por tiempo y segura para URL."},"encrypt-decrypt-text":{title:"Herramienta de cifrado y descifrado de texto",description:"Cifra y descifra texto usando algoritmos simétricos (AES, etc.) con claves y modos personalizados. Procesamiento seguro del lado del cliente."},"bip39-passphrase-generator":{title:"Generador de frase mnemónica BIP39",description:"Genera frases mnemónicas BIP39 seguras (12–24 palabras) para billeteras de criptomonedas con nivel de entropía seleccionable."},"hmac-generator":{title:"Generador de HMAC",description:"Calcula HMAC (código de autenticación de mensajes basado en hash) usando diversos algoritmos de hash y claves secretas para la integridad y autenticación de mensajes."},"rsa-key-pair-generator":{title:"Generador de par de claves RSA",description:"Genera pares de claves RSA pública/privada con longitud de bits seleccionable (2048, 4096, etc.) para cifrado, firma y SSH."},"password-strength-analyzer":{title:"Analizador de fortaleza de contraseñas",description:"Analiza la fortaleza de contraseñas en tiempo real: entropía, tiempo estimado de descifrado, detección de patrones comunes y comprobación de filtraciones."},"qr-code":{title:"Generador de códigos QR para URL y texto",description:"Crea códigos QR personalizables a partir de URL, texto, correos electrónicos o vCards. Descárgalos en varios formatos con corrección de errores y superposición de logotipos."},"wifi-qr-code":{title:"Generador de códigos QR de WiFi",description:"Genera códigos QR escaneables para redes WiFi. Admite WPA/WPA2, WEP, sin contraseña, SSID ocultos y configuraciones empresariales WPA2-EAP, con colores personalizados y descarga instantánea."},barcode:{title:"Generador de códigos de barras",description:"Genera códigos de barras personalizables en varios formatos (CODE128, EAN13, UPC, CODE39 y más). Ajusta el ancho de barra, la altura, los colores, los márgenes, la posición del texto, la fuente y el estilo. Vista previa en tiempo real con copia al portapapeles y descarga en PNG."},"contact-qr-code":{title:"Generador de códigos QR de contacto vCard",description:"Genera códigos QR profesionales con toda tu información de contacto (formato vCard). Incluye nombre, teléfono, correo electrónico, puesto de trabajo, sitio web, dirección y más. Perfecto para tarjetas de presentación, networking y compartir en digital."},"qr-code-reader":{title:"Lector / decodificador de QR y códigos de barras",description:"Escanea y decodifica códigos QR y códigos de barras 1D/2D al instante desde imágenes, archivos cargados o tu cámara web. Extrae URL, texto, datos de contacto, credenciales de Wi-Fi, información de productos y más, con resultados en tiempo real."},"json-yaml":{title:"Conversor de JSON a YAML en línea",description:"Convierte sin problemas entre JSON y YAML con validación y formato instantáneos. Perfecto para desarrolladores que trabajan con archivos de configuración e intercambio de datos."},"date-time":{title:"Conversor de formato de fecha y hora",description:"Transforma fechas y marcas de tiempo entre varios formatos, incluidas marcas de tiempo Unix, cadenas ISO y patrones personalizados. Ideal para depuración e integraciones con API."},"number-base":{title:"Conversor de base numérica",description:"Convierte rápidamente números entre bases binaria, hexadecimal, decimal y octal. Admite números grandes y cálculos en tiempo real para programadores e ingenieros."},"cron-parser":{title:"Analizador de expresiones cron",description:"Convierte expresiones cron en descripciones claras y legibles por humanos. Admite segundos, macros (@daily, @hourly, etc.), modo detallado, formato de 24 horas y explicaciones detalladas de símbolos para programar tareas."},html:{title:"Codificador y decodificador de entidades HTML",description:"Codifica o decodifica caracteres especiales en entidades HTML para prevenir vulnerabilidades XSS o mostrar texto con formato de manera segura en contenido web."},url:{title:"Codificador y decodificador de URL",description:"Codifica URL con codificación porcentual para una transmisión segura o decodifícalas de vuelta a texto legible. Esencial para el desarrollo web y el manejo de parámetros de API."},base64:{title:"Codificador y decodificador Base64 en línea",description:"Codifica datos binarios o texto a Base64 para adjuntos de correo y API, o decodifícalos fácilmente con validación incorporada."},jwt:{title:"Decodificador e inspector de tokens JWT",description:"Decodifica JSON Web Tokens para inspeccionar encabezados, cargas útiles y firmas sin claves secretas. Genial para depurar flujos de autenticación."},json:{title:"Formateador y validador de JSON",description:"Embellece, minifica y valida datos JSON en tiempo real. Detecta errores y asegúrate de que tu JSON sea sintácticamente correcto para una integración sin problemas."},xml:{title:"Formateador y embellecedor de XML",description:"Da formato a documentos XML para mejorar la legibilidad, contrae elementos anidados y valida la estructura. Útil para configuraciones XML e intercambio de datos."},sql:{title:"Formateador y embellecedor de SQL",description:"Formatea, embellece y aplica sangría a consultas SQL para mejorar la legibilidad. Admite sintaxis SQL estándar con sangría personalizable, palabras clave en mayúsculas y saltos de línea."},"lorem-ipsum":{title:"Generador de texto Lorem ipsum",description:"Produce texto de relleno personalizable en latín u otros idiomas. Especifica párrafos, palabras u oraciones para maquetas de diseño y prototipos."},checksum:{title:"Calculadora de checksum de archivos",description:"Calcula sumas de verificación de archivos o texto para verificar su integridad. Admite CRC32, MD5, SHA1, SHA256, SHA384 y SHA512 para descargas y respaldos."},"inspector-case-converter":{title:"Inspector de texto y conversor de mayúsculas y minúsculas",description:"Analiza estadísticas de texto como el conteo de palabras y la frecuencia de caracteres, mientras conviertes entre camelCase, snake_case, PascalCase y más para un código limpio."},regex:{title:"Probador y depurador de expresiones regulares",description:"Prueba y depura expresiones regulares con coincidencias en vivo, reemplazo y resaltado de sintaxis. Admite banderas y grupos de captura para una validación precisa de patrones."},"text-diff":{title:"Comparador de diferencias de texto",description:"Compara dos textos lado a lado o en línea con diferencias codificadas por colores. Perfecto para detectar cambios en código, configuraciones, registros o documentos con precisión a nivel de palabra y carácter."},"multi-language-translator":{title:"Traductor de JSON multilingüe",description:"Traduce palabras y frases a más de 11 idiomas al instante. Genera archivos common.json listos para usar en tu aplicación (i18n) con camelCase, snake_case o cualquier formato."},"markdown-editor":{title:"Editor y previsualizador de Markdown en vivo",description:"Escribe, edita y previsualiza Markdown en tiempo real con resaltado de sintaxis, renderizado en vivo, soporte para modo oscuro/claro y opciones de exportación. Perfecto para notas, README, documentación y publicaciones de blog."},"icon-generator":{title:"Generador de iconos de app con IA para iOS y Android",description:"Genera conjuntos completos de iconos de aplicación para iOS y Android a partir de una sola imagen de origen. Eliminación de fondo con IA para iconos transparentes, herramientas de rotación y volteo, plantillas de estilo modernas (Rounded, Squircle, Circle), carga desde URL o pegado desde el portapapeles, escalas personalizadas para exportaciones individuales en PNG/JPEG, color de fondo seleccionable para JPEG, y redimensionado y compresión de alta calidad."},"image-converter":{title:"Optimizador, conversor de imágenes y creador de PDF",description:"Convertidor de imágenes avanzado compatible con formatos modernos: AVIF, WebP, JPEG XL (JXL), MozJPEG, PNG y GIF animado. Control total sobre calidad, redimensionado, optimización, procesamiento por lotes, conversión entre formatos y combinación de imágenes en un solo PDF (solo PNG, JPG/JPEG, GIF y WebP)."},"pdf-to-images":{title:"Conversor de PDF a imágenes",description:"Extrae imágenes de alta calidad de archivos PDF página por página. Elige salida en PNG o JPEG, ajusta la resolución (72–288 DPI) y la calidad JPEG, procesa varios PDF por lotes, previsualiza páginas y descárgalas individualmente o en un ZIP."},"ip-geolocation":{title:"Búsqueda de geolocalización de direcciones IP",description:"Obtén al instante datos de geolocalización de cualquier dirección IP (o de tu IP actual). Incluye ciudad, región, país, zona horaria, ISP, latitud/longitud y más. Resultados exportables en varios formatos (JSON, XML, YAML, etc.)."}},fr:{"token-generator":{title:"Générateur de jetons aléatoires sécurisés",description:"Générez des jetons aléatoires cryptographiquement sûrs avec une longueur personnalisable (1–512 caractères) et des jeux de caractères au choix (majuscules, minuscules, chiffres, symboles). Idéal pour les clés API, les identifiants de session, les mots de passe ou tout besoin de jeton sécurisé."},"hash-text":{title:"Générateur de hachage de texte",description:"Générez des hachages sécurisés à partir de texte ou de fichiers avec les algorithmes MD5, SHA1, SHA256, SHA224, SHA512, SHA384, SHA3 et RIPEMD160. Idéal pour les contrôles d'intégrité des données et le hachage de mots de passe."},bcrypt:{title:"Générateur de hachage de mot de passe bcrypt",description:"Générez des hachages Bcrypt sécurisés pour les mots de passe avec un facteur de coût ajustable. Parfait pour le stockage sécurisé des mots de passe dans les applications."},"uuids-generator":{title:"Générateur d'UUID",description:"Générez des UUID de toutes versions : NIL (tout à zéro), v1 (basé sur le temps), v3 (basé sur un nom, MD5), v4 (aléatoire), v5 (basé sur un nom, SHA-1). Prend en charge la génération en masse (jusqu'à 50) et les espaces de noms personnalisés pour v3/v5."},"ulid-generator":{title:"Générateur d'ULID",description:"Générez des identifiants universellement uniques et triables lexicographiquement (ULID). Une alternative aux UUID, monotone, triable par date et compatible URL."},"encrypt-decrypt-text":{title:"Outil de chiffrement et déchiffrement de texte",description:"Chiffrez et déchiffrez du texte avec des algorithmes symétriques (AES, etc.), des clés et des modes personnalisés. Traitement sécurisé côté client."},"bip39-passphrase-generator":{title:"Générateur de phrase mnémonique BIP39",description:"Générez des phrases mnémoniques BIP39 sécurisées (12–24 mots) pour les portefeuilles de cryptomonnaies avec un niveau d'entropie sélectionnable."},"hmac-generator":{title:"Générateur HMAC",description:"Calculez un HMAC (code d'authentification de message basé sur le hachage) avec divers algorithmes de hachage et des clés secrètes pour l'intégrité et l'authentification des messages."},"rsa-key-pair-generator":{title:"Générateur de paire de clés RSA",description:"Générez des paires de clés RSA publique/privée avec une longueur en bits sélectionnable (2048, 4096, etc.) pour le chiffrement, la signature et SSH."},"password-strength-analyzer":{title:"Analyseur de robustesse de mot de passe",description:"Analysez la robustesse des mots de passe en temps réel : entropie, estimation du temps de cassage, détection de motifs courants et vérifications de fuites."},"qr-code":{title:"Générateur de QR code pour URL et texte",description:"Créez des codes QR personnalisables à partir d'URL, de texte, d'e-mails ou de vCards. Téléchargez-les en plusieurs formats avec correction d'erreur et superposition de logo."},"wifi-qr-code":{title:"Générateur de QR code WiFi",description:"Générez des codes QR scannables pour les réseaux WiFi. Prend en charge WPA/WPA2, WEP, l'absence de mot de passe, les SSID masqués et les configurations d'entreprise WPA2-EAP, avec couleurs personnalisées et téléchargement instantané."},barcode:{title:"Générateur de code-barres",description:"Générez des codes-barres personnalisables en plusieurs formats (CODE128, EAN13, UPC, CODE39 et plus). Ajustez la largeur des barres, la hauteur, les couleurs, les marges, la position du texte, la police et le style. Aperçu en temps réel avec copie dans le presse-papiers et téléchargement en PNG."},"contact-qr-code":{title:"Générateur de QR code de contact vCard",description:"Générez des codes QR professionnels contenant toutes vos coordonnées (format vCard). Incluez nom, téléphone, e-mail, fonction, site web, adresse et plus encore. Parfait pour les cartes de visite, le réseautage et le partage numérique."},"qr-code-reader":{title:"Lecteur / décodeur de QR code et code-barres",description:"Scannez et décodez instantanément des codes QR et des codes-barres 1D/2D depuis des images, des fichiers ou votre webcam. Extrayez des URL, du texte, des coordonnées, des identifiants Wi-Fi, des informations produit et plus encore avec des résultats en temps réel."},"json-yaml":{title:"Convertisseur JSON vers YAML en ligne",description:"Convertissez facilement JSON en YAML et YAML en JSON avec validation et formatage instantanés. Parfait pour les développeurs qui manipulent des fichiers de configuration et des échanges de données."},"date-time":{title:"Convertisseur de format de date et heure",description:"Transformez des dates et horodatages entre divers formats, y compris les horodatages Unix, les chaînes ISO et les motifs personnalisés. Idéal pour le débogage et les intégrations API."},"number-base":{title:"Convertisseur de base numérique",description:"Convertissez rapidement des nombres entre les bases binaire, hexadécimale, décimale et octale. Prend en charge les grands nombres et les calculs en temps réel pour les programmeurs et les ingénieurs."},"cron-parser":{title:"Analyseur d'expression cron",description:"Analysez les expressions cron en descriptions claires et lisibles. Prend en charge les secondes, les macros (@daily, @hourly, etc.), le mode détaillé, le format 24 heures et des explications détaillées des symboles pour planifier des tâches."},html:{title:"Encodeur et décodeur d'entités HTML",description:"Encodez ou décodez les caractères spéciaux en entités HTML pour prévenir les vulnérabilités XSS ou afficher du texte formaté en toute sécurité dans le contenu web."},url:{title:"Encodeur et décodeur d'URL",description:"Encodez les URL avec l'encodage pourcent pour une transmission sûre ou décodez-les en texte lisible. Indispensable pour le développement web et la gestion des paramètres d'API."},base64:{title:"Encodeur et décodeur Base64 en ligne",description:"Encodez des données binaires ou du texte en Base64 pour les pièces jointes d'e-mails et les API, ou décodez-les facilement avec une validation intégrée."},jwt:{title:"Décodeur et inspecteur de jeton JWT",description:"Décodez les JSON Web Tokens pour inspecter les en-têtes, charges utiles et signatures sans clé secrète. Idéal pour déboguer les flux d'authentification."},json:{title:"Formateur et validateur JSON",description:"Embellissez, minifiez et validez des données JSON en temps réel. Détectez les erreurs et assurez-vous que votre JSON est syntaxiquement correct pour une intégration sans accroc."},xml:{title:"Formateur et indenteur XML",description:"Formatez les documents XML pour plus de lisibilité, repliez les éléments imbriqués et validez la structure. Utile pour la configuration XML et l'échange de données."},sql:{title:"Formateur et embellisseur SQL",description:"Formatez, embellissez et indentez les requêtes SQL pour une meilleure lisibilité. Prend en charge la syntaxe SQL standard avec indentation personnalisable, mots-clés en majuscules et sauts de ligne."},"lorem-ipsum":{title:"Générateur de texte Lorem Ipsum",description:"Produisez du texte de remplissage personnalisable en latin ou dans d'autres langues. Spécifiez des paragraphes, des mots ou des phrases pour les maquettes de conception et le prototypage."},checksum:{title:"Calculateur de somme de contrôle de fichier",description:"Calculez des sommes de contrôle pour des fichiers ou du texte afin de vérifier leur intégrité. Prend en charge CRC32, MD5, SHA1, SHA256, SHA384 et SHA512 pour les téléchargements et les sauvegardes."},"inspector-case-converter":{title:"Inspecteur de texte et convertisseur de casse",description:"Analysez les statistiques de texte comme le nombre de mots et la fréquence des caractères, tout en convertissant entre camelCase, snake_case, PascalCase et plus pour un code propre."},regex:{title:"Testeur et débogueur d'expressions régulières",description:"Testez et déboguez des expressions régulières avec correspondance en direct, remplacement et coloration syntaxique. Prend en charge les drapeaux et les groupes de capture pour une validation précise des motifs."},"text-diff":{title:"Vérificateur et comparateur de différences de texte",description:"Comparez deux textes côte à côte ou en ligne avec des différences en couleur. Parfait pour repérer les changements dans le code, les configurations, les journaux ou les documents avec une précision au mot et au caractère près."},"multi-language-translator":{title:"Traducteur JSON multilingue",description:"Traduisez instantanément des mots et des phrases dans plus de 11 langues. Générez des fichiers common.json prêts à l'emploi pour votre application (i18n) avec camelCase, snake_case ou tout autre format."},"markdown-editor":{title:"Éditeur et prévisualiseur Markdown en direct",description:"Écrivez, modifiez et prévisualisez du Markdown en temps réel avec coloration syntaxique, rendu en direct, mode sombre/clair et options d'exportation. Parfait pour les notes, les README, la documentation et les articles de blog."},"icon-generator":{title:"Générateur d'icônes d'application IA pour iOS et Android",description:"Générez des jeux d'icônes d'application complets pour iOS et Android à partir d'une seule image source. Suppression d'arrière-plan par IA pour des icônes transparentes, outils de rotation et de retournement, modèles de style modernes (arrondi, squircle, cercle), import depuis une URL ou collage depuis le presse-papiers, échelles personnalisées pour les exports PNG/JPEG individuels, couleur d'arrière-plan sélectionnable pour le JPEG, redimensionnement et compression haute qualité."},"image-converter":{title:"Optimiseur, convertisseur d'images et créateur de PDF",description:"Convertisseur d'images avancé prenant en charge les formats modernes : AVIF, WebP, JPEG XL (JXL), MozJPEG, PNG et GIF animé. Contrôle total sur la qualité, le redimensionnement, l'optimisation, le traitement par lots, la conversion entre formats et la combinaison d'images en un seul PDF (PNG, JPG/JPEG, GIF, WebP uniquement)."},"pdf-to-images":{title:"Convertisseur de PDF en images",description:"Extrayez des images de haute qualité depuis des fichiers PDF, page par page. Choisissez une sortie PNG ou JPEG, ajustez la résolution (72–288 DPI) et la qualité JPEG, traitez plusieurs PDF par lots, prévisualisez les pages et téléchargez individuellement ou en ZIP."},"ip-geolocation":{title:"Géolocalisation d'adresse IP",description:"Obtenez instantanément les données de géolocalisation de n'importe quelle adresse IP (ou de votre IP actuelle). Inclut la ville, la région, le pays, le fuseau horaire, le ISP, la latitude/longitude et plus encore. Résultats exportables en plusieurs formats (JSON, XML, YAML, etc.)."}},de:{"token-generator":{title:"Generator für sichere Zufalls-Tokens",description:"Erzeugen Sie kryptografisch sichere Zufallstokens mit anpassbarer Länge (1–512 Zeichen) und Zeichensätzen (Großbuchstaben, Kleinbuchstaben, Zahlen, Sonderzeichen). Ideal für API-Schlüssel, Sitzungs-IDs, Passwörter oder andere sichere Token-Anforderungen."},"hash-text":{title:"Text-Hash-Generator",description:"Erzeugen Sie sichere Hashes aus Text oder Dateien mit den Algorithmen MD5, SHA1, SHA256, SHA224, SHA512, SHA384, SHA3 und RIPEMD160. Ideal für Datenintegritätsprüfungen und Passwort-Hashing."},bcrypt:{title:"Bcrypt-Passwort-Hash-Generator",description:"Erzeugen Sie sichere Bcrypt-Hashes für Passwörter mit anpassbarem Kostenfaktor. Perfekt für die sichere Passwortspeicherung in Anwendungen."},"uuids-generator":{title:"UUID-Generator",description:"Erzeugen Sie UUIDs aller Versionen: NIL (nur Nullen), v1 (zeitbasiert), v3 (namensbasiert mit MD5), v4 (zufällig), v5 (namensbasiert mit SHA-1). Unterstützt Massenerzeugung (bis zu 50) und benutzerdefinierte Namespaces für v3/v5."},"ulid-generator":{title:"ULID-Generator",description:"Erzeugen Sie Universally Unique Lexicographically Sortable Identifiers (ULID). Eine monotone, zeitlich sortierbare und URL-sichere Alternative zu UUIDs."},"encrypt-decrypt-text":{title:"Tool zum Verschlüsseln & Entschlüsseln von Text",description:"Verschlüsseln und entschlüsseln Sie Text mit symmetrischen Algorithmen (AES usw.) mit eigenen Schlüsseln und Modi. Sichere clientseitige Verarbeitung."},"bip39-passphrase-generator":{title:"BIP39-Mnemonik-Generator",description:"Erzeugen Sie sichere BIP39-Mnemonik-Phrasen (12–24 Wörter) für Kryptowährungs-Wallets mit wählbarer Entropiestärke."},"hmac-generator":{title:"HMAC-Generator",description:"Berechnen Sie HMAC (Hash-based Message Authentication Code) mit verschiedenen Hash-Algorithmen und geheimen Schlüsseln für Nachrichtenintegrität und Authentifizierung."},"rsa-key-pair-generator":{title:"RSA-Schlüsselpaar-Generator",description:"Erzeugen Sie öffentliche/private RSA-Schlüsselpaare mit wählbarer Bitlänge (2048, 4096 usw.) für Verschlüsselung, Signierung und SSH."},"password-strength-analyzer":{title:"Passwortstärke-Analysator",description:"Analysieren Sie die Passwortstärke in Echtzeit: Entropie, geschätzte Knackdauer, Erkennung gängiger Muster und Leak-Prüfungen."},"qr-code":{title:"QR-Code-Generator für URLs und Text",description:"Erstellen Sie anpassbare QR-Codes aus URLs, Text, E-Mails oder vCards. Download in mehreren Formaten mit Fehlerkorrektur und Logo-Overlays."},"wifi-qr-code":{title:"WLAN-QR-Code-Generator",description:"Erzeugen Sie scannbare QR-Codes für WiFi-Netzwerke. Unterstützt WPA/WPA2, WEP, kein Passwort, versteckte SSIDs und WPA2-EAP-Unternehmenskonfigurationen mit eigenen Farben und sofortigem Download."},barcode:{title:"Barcode-Generator",description:"Erzeugen Sie anpassbare Barcodes in mehreren Formaten (CODE128, EAN13, UPC, CODE39 und mehr). Passen Sie Strichbreite, Höhe, Farben, Ränder, Textposition, Schrift und Stil an. Echtzeitvorschau mit Kopieren in die Zwischenablage und PNG-Download."},"contact-qr-code":{title:"vCard-Kontakt-QR-Code-Generator",description:"Erzeugen Sie professionelle QR-Codes mit Ihren vollständigen Kontaktinformationen (vCard-Format). Inklusive Name, Telefon, E-Mail, Berufsbezeichnung, Website, Adresse und mehr. Perfekt für Visitenkarten, Networking und digitales Teilen."},"qr-code-reader":{title:"QR- & Barcode-Leser / -Decoder",description:"Scannen und dekodieren Sie QR-Codes und 1D-/2D-Barcodes sofort aus Bildern, hochgeladenen Dateien oder Ihrer Webcam. Extrahieren Sie URLs, Text, Kontaktdaten, Wi-Fi-Zugangsdaten, Produktinformationen und mehr mit Echtzeitergebnissen."},"json-yaml":{title:"JSON-zu-YAML-Konverter online",description:"Konvertieren Sie nahtlos JSON zu YAML und YAML zu JSON mit sofortiger Validierung und Formatierung. Perfekt für Entwickler, die mit Konfigurationsdateien und Datenaustausch arbeiten."},"date-time":{title:"Datums- und Zeitformat-Konverter",description:"Wandeln Sie Datumsangaben und Zeitstempel zwischen verschiedenen Formaten um, einschließlich Unix-Zeitstempeln, ISO-Zeichenketten und eigenen Mustern. Ideal für Debugging und API-Integrationen."},"number-base":{title:"Zahlenbasis-Konverter",description:"Konvertieren Sie Zahlen schnell zwischen Binär-, Hexadezimal-, Dezimal- und Oktalsystem. Unterstützt große Zahlen und Echtzeitberechnungen für Programmierer und Ingenieure."},"cron-parser":{title:"Cron-Ausdruck-Parser",description:"Übersetzen Sie cron-Ausdrücke in klare, gut lesbare Beschreibungen. Unterstützt Sekunden, Makros (@daily, @hourly usw.), ausführlichen Modus, 24-Stunden-Format und detaillierte Symbolerklärungen für die Aufgabenplanung."},html:{title:"HTML-Entity-Encoder und -Decoder",description:"Kodieren oder dekodieren Sie Sonderzeichen zu HTML-Entitäten, um XSS-Schwachstellen zu verhindern oder formatierten Text sicher in Webinhalten darzustellen."},url:{title:"URL-Encoder und -Decoder",description:"Kodieren Sie URLs mit Prozentkodierung für eine sichere Übertragung oder dekodieren Sie sie zurück in lesbaren Text. Unverzichtbar für Webentwicklung und API-Parameterverarbeitung."},base64:{title:"Base64-Encoder und -Decoder online",description:"Kodieren Sie Binärdaten oder Text zu Base64 für E-Mail-Anhänge und APIs oder dekodieren Sie sie mühelos zurück — mit integrierter Validierung."},jwt:{title:"JWT-Token-Decoder und -Inspektor",description:"Dekodieren Sie JSON Web Tokens, um Header, Payloads und Signaturen ohne geheime Schlüssel zu untersuchen. Ideal zum Debuggen von Authentifizierungsabläufen."},json:{title:"JSON-Formatierer und -Validierer",description:"Verschönern, minimieren und validieren Sie JSON-Daten in Echtzeit. Erkennen Sie Fehler und stellen Sie sicher, dass Ihr JSON syntaktisch korrekt für eine nahtlose Integration ist."},xml:{title:"XML-Formatierer und Pretty Printer",description:"Formatieren Sie XML-Dokumente für bessere Lesbarkeit, klappen Sie verschachtelte Elemente ein und validieren Sie die Struktur. Nützlich für XML-Konfiguration und Datenaustausch."},sql:{title:"SQL-Formatierer und -Verschönerer",description:"Formatieren, verschönern und rücken Sie SQL-Abfragen für bessere Lesbarkeit ein. Unterstützt Standard-SQL-Syntax mit anpassbarer Einrückung, Schlüsselwörtern in Großbuchstaben und Zeilenumbrüchen."},"lorem-ipsum":{title:"Lorem-Ipsum-Textgenerator",description:"Erzeugen Sie anpassbaren Platzhaltertext in Latein oder anderen Sprachen. Legen Sie Absätze, Wörter oder Sätze für Design-Mockups und Prototyping fest."},checksum:{title:"Datei-Prüfsummen-Rechner",description:"Berechnen Sie Prüfsummen für Dateien oder Text, um die Integrität zu verifizieren. Unterstützt CRC32, MD5, SHA1, SHA256, SHA384 und SHA512 für Downloads und Backups."},"inspector-case-converter":{title:"Tool zur Textanalyse und Groß-/Kleinschreibung-Umwandlung",description:"Analysieren Sie Textstatistiken wie Wortanzahl und Zeichenhäufigkeit und konvertieren Sie zwischen camelCase, snake_case, PascalCase und mehr für sauberen Code."},regex:{title:"Tester und Debugger für reguläre Ausdrücke",description:"Testen und debuggen Sie reguläre Ausdrücke mit Live-Abgleich, Ersetzung und Syntaxhervorhebung. Unterstützt Flags und Erfassungsgruppen für präzise Mustervalidierung."},"text-diff":{title:"Textunterschied-Prüfer und -Vergleicher",description:"Vergleichen Sie zwei Texte nebeneinander oder inline mit farbcodierten Unterschieden. Perfekt, um Änderungen in Code, Konfigurationen, Logs oder Dokumenten mit Wort- und Zeichengenauigkeit zu erkennen."},"multi-language-translator":{title:"Mehrsprachiger JSON-Übersetzer",description:"Übersetzen Sie Wörter und Phrasen sofort in 11+ Sprachen. Erzeugen Sie einsatzbereite common.json-Dateien für Ihre App (i18n) mit camelCase, snake_case oder jedem beliebigen Format."},"markdown-editor":{title:"Live-Markdown-Editor & -Vorschau",description:"Schreiben, bearbeiten und betrachten Sie Markdown in Echtzeit mit Syntaxhervorhebung, Live-Rendering, Unterstützung für Dunkel-/Hellmodus und Exportoptionen. Perfekt für Notizen, READMEs, Dokumentation und Blogbeiträge."},"icon-generator":{title:"KI-App-Icon-Generator für iOS & Android",description:"Erzeugen Sie vollständige App-Icon-Sets für iOS und Android aus einem einzigen Quellbild. KI-gestützte Hintergrundentfernung für transparente Icons, Dreh- und Spiegelwerkzeuge, moderne Stilvorlagen (Rounded, Squircle, Circle), Upload per URL oder Einfügen aus der Zwischenablage, eigene Skalierungen für einzelne PNG-/JPEG-Exporte, wählbare Hintergrundfarbe für JPEG, hochwertige Größenänderung & Komprimierung."},"image-converter":{title:"Bildoptimierer, -konverter und PDF-Ersteller",description:"Fortschrittlicher Bildkonverter mit Unterstützung moderner Formate: AVIF, WebP, JPEG XL (JXL), MozJPEG, PNG und animierte GIF. Volle Kontrolle über Qualität, Größenänderung, Optimierung, Stapelverarbeitung, formatübergreifende Konvertierung und das Zusammenführen von Bildern in ein einziges PDF (nur PNG, JPG/JPEG, GIF, WebP)."},"pdf-to-images":{title:"PDF-zu-Bilder-Konverter",description:"Extrahieren Sie hochwertige Bilder Seite für Seite aus PDF-Dateien. Wählen Sie PNG- oder JPEG-Ausgabe, passen Sie die Auflösung (72–288 DPI) und die JPEG-Qualität an, verarbeiten Sie mehrere PDFs im Stapel, sehen Sie Seiten in der Vorschau und laden Sie sie einzeln oder als ZIP herunter."},"ip-geolocation":{title:"IP-Adressen-Geolokalisierung",description:"Rufen Sie sofort Geolokalisierungsdaten zu jeder IP-Adresse (oder Ihrer aktuellen IP) ab. Inklusive Stadt, Region, Land, Zeitzone, ISP, Breiten-/Längengrad und mehr. Ergebnisse sind in mehreren Formaten exportierbar (JSON, XML, YAML usw.)."}},it:{"token-generator":{title:"Generatore di Token Casuali Sicuri",description:"Genera token casuali crittograficamente sicuri con lunghezza personalizzabile (1–512 caratteri) e set di caratteri (maiuscole, minuscole, numeri, simboli). Ideale per chiavi API, ID di sessione, password o qualsiasi esigenza di token sicuri."},"hash-text":{title:"Generatore di Hash di Testo",description:"Genera hash sicuri da testo o file usando gli algoritmi MD5, SHA1, SHA256, SHA224, SHA512, SHA384, SHA3 e RIPEMD160. Ideale per i controlli di integrità dei dati e l'hashing delle password."},bcrypt:{title:"Generatore di Hash di Password bcrypt",description:"Genera hash Bcrypt sicuri per le password con fattore di costo regolabile. Perfetto per l'archiviazione sicura delle password nelle applicazioni."},"uuids-generator":{title:"Generatore di UUID",description:"Genera UUID di tutte le versioni: NIL (tutti zeri), v1 (basato sul tempo), v3 (basato su nome, MD5), v4 (casuale), v5 (basato su nome, SHA-1). Supporta la generazione in blocco (fino a 50) e namespace personalizzati per v3/v5."},"ulid-generator":{title:"Generatore di ULID",description:"Genera identificatori universalmente unici ordinabili lessicograficamente (ULID). Alternativa agli UUID monotona, ordinabile per tempo e sicura per gli URL."},"encrypt-decrypt-text":{title:"Strumento di Cifratura e Decifratura del Testo",description:"Cifra e decifra testo usando algoritmi simmetrici (AES, ecc.) con chiavi e modalità personalizzate. Elaborazione sicura lato client."},"bip39-passphrase-generator":{title:"Generatore di Frasi Mnemoniche BIP39",description:"Genera frasi mnemoniche BIP39 sicure (12–24 parole) per portafogli di criptovalute con livello di entropia selezionabile."},"hmac-generator":{title:"Generatore di HMAC",description:"Calcola HMAC (Hash-based Message Authentication Code) usando vari algoritmi di hash e chiavi segrete per l'integrità e l'autenticazione dei messaggi."},"rsa-key-pair-generator":{title:"Generatore di Coppie di Chiavi RSA",description:"Genera coppie di chiavi RSA pubblica/privata con lunghezza in bit selezionabile (2048, 4096, ecc.) per crittografia, firma e SSH."},"password-strength-analyzer":{title:"Analizzatore della Robustezza delle Password",description:"Analizza la robustezza delle password in tempo reale: entropia, stima del tempo di violazione, rilevamento di pattern comuni e controllo delle violazioni."},"qr-code":{title:"Generatore di QR Code per URL e Testo",description:"Crea codici QR personalizzabili da URL, testo, email o vCard. Scaricali in più formati con correzione degli errori e sovrapposizione del logo."},"wifi-qr-code":{title:"Generatore di QR Code WiFi",description:"Genera codici QR scansionabili per le reti WiFi. Supporta WPA/WPA2, WEP, nessuna password, SSID nascosti e configurazioni aziendali WPA2-EAP con colori personalizzati e download immediato."},barcode:{title:"Generatore di Codici a Barre",description:"Genera codici a barre personalizzabili in più formati (CODE128, EAN13, UPC, CODE39 e altri). Regola larghezza delle barre, altezza, colori, margini, posizione del testo, carattere e stile. Anteprima in tempo reale con copia negli appunti e download PNG."},"contact-qr-code":{title:"Generatore di QR Code Contatto vCard",description:"Genera codici QR professionali contenenti tutte le tue informazioni di contatto (formato vCard). Includi nome, telefono, email, ruolo professionale, sito web, indirizzo e altro. Perfetto per biglietti da visita, networking e condivisione digitale."},"qr-code-reader":{title:"Lettore / Decodificatore di QR Code e Codici a Barre",description:"Scansiona e decodifica istantaneamente codici QR e codici a barre 1D/2D da immagini, file caricati o dalla tua webcam. Estrai URL, testo, informazioni di contatto, credenziali Wi-Fi, informazioni sui prodotti e altro con risultati in tempo reale."},"json-yaml":{title:"Convertitore da JSON a YAML Online",description:"Converti senza problemi JSON in YAML e YAML in JSON con convalida e formattazione istantanee. Perfetto per gli sviluppatori che gestiscono file di configurazione e scambio di dati."},"date-time":{title:"Convertitore di Formato Data e Ora",description:"Trasforma date e timestamp tra vari formati, inclusi timestamp Unix, stringhe ISO e pattern personalizzati. Ideale per il debug e le integrazioni API."},"number-base":{title:"Convertitore di Base Numerica",description:"Converti rapidamente numeri tra basi binaria, esadecimale, decimale e ottale. Supporta numeri grandi e calcoli in tempo reale per programmatori e ingegneri."},"cron-parser":{title:"Parser di Espressioni cron",description:"Analizza le espressioni cron in descrizioni chiare e leggibili. Supporta i secondi, le macro (@daily, @hourly, ecc.), la modalità dettagliata, il formato a 24 ore e spiegazioni dettagliate dei simboli per la pianificazione delle attività."},html:{title:"Codificatore e Decodificatore di Entità HTML",description:"Codifica o decodifica caratteri speciali in entità HTML per prevenire vulnerabilità XSS o visualizzare in sicurezza testo formattato nei contenuti web."},url:{title:"Codificatore e Decodificatore di URL",description:"Codifica gli URL con la codifica percentuale per una trasmissione sicura o decodificali in testo leggibile. Essenziale per lo sviluppo web e la gestione dei parametri delle API."},base64:{title:"Codificatore e Decodificatore Base64 Online",description:"Codifica dati binari o testo in Base64 per allegati email e API, oppure decodificali facilmente con convalida integrata."},jwt:{title:"Decodificatore e Ispettore di Token JWT",description:"Decodifica i JSON Web Token per ispezionare header, payload e firme senza chiavi segrete. Ottimo per il debug dei flussi di autenticazione."},json:{title:"Formattatore e Validatore JSON",description:"Abbellisci, minifica e convalida dati JSON in tempo reale. Rileva gli errori e assicurati che il tuo JSON sia sintatticamente corretto per un'integrazione senza problemi."},xml:{title:"Formattatore e Abbellitore XML",description:"Formatta documenti XML per la leggibilità, comprimi gli elementi annidati e convalida la struttura. Utile per configurazioni XML e scambio di dati."},sql:{title:"Formattatore e Abbellitore SQL",description:"Formatta, abbellisci e indenta le query SQL per una migliore leggibilità. Supporta la sintassi SQL standard con indentazione personalizzabile, parole chiave in maiuscolo e interruzioni di riga."},"lorem-ipsum":{title:"Generatore di Testo Lorem Ipsum",description:"Produci testo segnaposto personalizzabile in latino o altre lingue. Specifica paragrafi, parole o frasi per mockup di design e prototipazione."},checksum:{title:"Calcolatore di Checksum dei File",description:"Calcola i checksum di file o testo per verificarne l'integrità. Supporta CRC32, MD5, SHA1, SHA256, SHA384 e SHA512 per download e backup."},"inspector-case-converter":{title:"Ispettore di Testo e Convertitore di Maiuscole/Minuscole",description:"Analizza statistiche del testo come conteggio delle parole e frequenza dei caratteri, convertendo tra camelCase, snake_case, PascalCase e altro per un codice pulito."},regex:{title:"Tester e Debugger di Espressioni Regolari",description:"Testa ed esegui il debug delle espressioni regolari con corrispondenza in tempo reale, sostituzione ed evidenziazione della sintassi. Supporta flag e gruppi di cattura per una convalida precisa dei pattern."},"text-diff":{title:"Verificatore e Comparatore di Differenze di Testo",description:"Confronta due testi affiancati o in linea con differenze codificate per colore. Perfetto per individuare modifiche in codice, configurazioni, log o documenti con precisione a livello di parola e carattere."},"multi-language-translator":{title:"Traduttore JSON Multilingua",description:"Traduci parole e frasi in oltre 11 lingue all'istante. Genera file common.json pronti all'uso per la tua app (i18n) con camelCase, snake_case o qualsiasi formato."},"markdown-editor":{title:"Editor e Anteprima Markdown in Tempo Reale",description:"Scrivi, modifica e visualizza l'anteprima del Markdown in tempo reale con evidenziazione della sintassi, rendering live, supporto per modalità scura/chiara e opzioni di esportazione. Perfetto per note, README, documentazione e post di blog."},"icon-generator":{title:"Generatore IA di Icone App per iOS e Android",description:"Genera set completi di icone per app iOS e Android da una singola immagine sorgente. Rimozione dello sfondo basata su IA per icone trasparenti, strumenti di rotazione e capovolgimento, modelli di stile moderni (Rounded, Squircle, Circle), caricamento da URL o incolla dagli appunti, scale personalizzate per esportazioni singole PNG/JPEG, colore di sfondo selezionabile per JPEG, ridimensionamento e compressione di alta qualità."},"image-converter":{title:"Ottimizzatore, Convertitore di Immagini e Creatore di PDF",description:"Convertitore di immagini avanzato che supporta i formati moderni: AVIF, WebP, JPEG XL (JXL), MozJPEG, PNG e GIF animate. Controllo completo su qualità, ridimensionamento, ottimizzazione, elaborazione in batch, conversione tra formati e combinazione di immagini in un unico PDF (solo PNG, JPG/JPEG, GIF, WebP)."},"pdf-to-images":{title:"Convertitore da PDF a Immagini",description:"Estrai immagini di alta qualità dai file PDF pagina per pagina. Scegli l'output PNG o JPEG, regola la risoluzione (72–288 DPI) e la qualità JPEG, elabora più PDF in batch, visualizza l'anteprima delle pagine e scaricale singolarmente o come ZIP."},"ip-geolocation":{title:"Ricerca di Geolocalizzazione di Indirizzi IP",description:"Recupera istantaneamente i dati di geolocalizzazione per qualsiasi indirizzo IP (o per il tuo IP attuale). Include città, regione, paese, fuso orario, ISP, latitudine/longitudine e altro. Risultati esportabili in più formati (JSON, XML, YAML, ecc.)."}},ja:{"token-generator":{title:"セキュアなランダムトークンジェネレーター",description:"暗号学的に安全なランダムトークンを生成。長さ（1〜512文字）と文字セット（大文字、小文字、数字、記号）をカスタマイズ可能。APIキー、セッションID、パスワードなど、あらゆるセキュアトークンの用途に最適。"},"hash-text":{title:"テキストハッシュジェネレーター",description:"MD5、SHA1、SHA256、SHA224、SHA512、SHA384、SHA3、RIPEMD160アルゴリズムを使用してテキストやファイルから安全なハッシュを生成。データ整合性チェックやパスワードハッシュに最適。"},bcrypt:{title:"bcrypt パスワードハッシュジェネレーター",description:"コストファクターを調整可能なパスワード用の安全なBcryptハッシュを生成。アプリケーションでの安全なパスワード保存に最適。"},"uuids-generator":{title:"UUID ジェネレーター",description:"全バージョンのUUIDを生成：NIL（全ゼロ）、v1（時刻ベース）、v3（名前ベースMD5）、v4（ランダム）、v5（名前ベースSHA-1）。一括生成（最大50件）、v3/v5のカスタム名前空間に対応。"},"ulid-generator":{title:"ULID ジェネレーター",description:"ULID（辞書順ソート可能な汎用一意識別子）を生成。単調増加、時刻順ソート可能、URLセーフなUUIDの代替。"},"encrypt-decrypt-text":{title:"テキスト暗号化・復号ツール",description:"対称アルゴリズム（AESなど）でカスタムキーとモードを使用してテキストを暗号化・復号。安全なクライアントサイド処理。"},"bip39-passphrase-generator":{title:"BIP39 ニーモニックフレーズジェネレーター",description:"暗号資産ウォレット用の安全なBIP39ニーモニックフレーズ（12〜24語）をエントロピー強度を選択して生成。"},"hmac-generator":{title:"HMAC ジェネレーター",description:"さまざまなハッシュアルゴリズムと秘密鍵を使用してHMAC（ハッシュベースメッセージ認証コード）を計算。メッセージの整合性と認証に。"},"rsa-key-pair-generator":{title:"RSA 鍵ペアジェネレーター",description:"ビット長（2048、4096など）を選択してRSA公開鍵/秘密鍵ペアを生成。暗号化、署名、SSHに。"},"password-strength-analyzer":{title:"パスワード強度アナライザー",description:"パスワード強度をリアルタイムで分析：エントロピー、解読時間の推定、一般的なパターンの検出、漏洩チェック。"},"qr-code":{title:"URL・テキスト用 QR コードジェネレーター",description:"URL、テキスト、メール、vCardからカスタマイズ可能なQRコードを作成。誤り訂正とロゴ重ね合わせに対応し、複数形式でダウンロード可能。"},"wifi-qr-code":{title:"WiFi QR コードジェネレーター",description:"WiFiネットワーク用のスキャン可能なQRコードを生成。WPA/WPA2、WEP、パスワードなし、非表示SSID、エンタープライズWPA2-EAP構成に対応。カスタムカラーと即時ダウンロード。"},barcode:{title:"バーコードジェネレーター",description:"複数形式（CODE128、EAN13、UPC、CODE39など）のカスタマイズ可能なバーコードを生成。バー幅、高さ、色、余白、テキスト位置、フォント、スタイルを調整。リアルタイムプレビュー、クリップボードコピー、PNGダウンロード対応。"},"contact-qr-code":{title:"vCard 連絡先 QR コードジェネレーター",description:"完全な連絡先情報（vCard形式）を含むプロフェッショナルなQRコードを生成。氏名、電話、メール、役職、ウェブサイト、住所などを収録。名刺、ネットワーキング、デジタル共有に最適。"},"qr-code-reader":{title:"QR・バーコードリーダー / デコーダー",description:"画像、アップロードファイル、ウェブカメラからQRコードや1D/2Dバーコードを即座にスキャン・デコード。URL、テキスト、連絡先、Wi-Fi認証情報、製品情報などをリアルタイムで抽出。"},"json-yaml":{title:"JSON から YAML への変換ツール（オンライン）",description:"JSONからYAML、YAMLからJSONへ即時検証・整形付きでシームレスに変換。設定ファイルやデータ交換を扱う開発者に最適。"},"date-time":{title:"日付・時刻フォーマット変換ツール",description:"Unixタイムスタンプ、ISO文字列、カスタムパターンなど、さまざまな形式間で日付とタイムスタンプを変換。デバッグやAPI連携に最適。"},"number-base":{title:"進数変換ツール",description:"2進数、16進数、10進数、8進数間で数値を素早く変換。大きな数値とリアルタイム計算に対応。プログラマーとエンジニア向け。"},"cron-parser":{title:"cron 式パーサー",description:"cron式をわかりやすい説明文に解析。秒、マクロ（@daily、@hourlyなど）、詳細モード、24時間形式、記号の詳しい解説に対応。タスクスケジューリングに。"},html:{title:"HTML エンティティのエンコード・デコードツール",description:"特殊文字をHTMLエンティティにエンコード/デコード。XSS脆弱性の防止やウェブコンテンツでの安全な整形テキスト表示に。"},url:{title:"URL エンコード・デコードツール",description:"URLをパーセントエンコーディングで安全に変換、または読みやすいテキストにデコード。ウェブ開発やAPIパラメータ処理に必須。"},base64:{title:"Base64 エンコード・デコードツール（オンライン）",description:"バイナリデータやテキストをメール添付やAPI用にBase64エンコード、または組み込み検証付きで簡単にデコード。"},jwt:{title:"JWT トークンデコーダー・インスペクター",description:"JSON Web Tokenをデコードし、秘密鍵なしでヘッダー、ペイロード、署名を確認。認証フローのデバッグに最適。"},json:{title:"JSON フォーマッター・バリデーター",description:"JSONデータをリアルタイムで整形、圧縮、検証。エラーを検出し、構文的に正しいJSONでシームレスな連携を実現。"},xml:{title:"XML フォーマッター・整形ツール",description:"XMLドキュメントを読みやすく整形、ネストされた要素の折りたたみ、構造の検証。XML設定やデータ交換に便利。"},sql:{title:"SQL フォーマッター・整形ツール",description:"SQLクエリを整形・美化・インデントして可読性を向上。標準SQL構文に対応し、インデント、キーワードの大文字化、改行をカスタマイズ可能。"},"lorem-ipsum":{title:"Lorem ipsum テキストジェネレーター",description:"ラテン語などのカスタマイズ可能なプレースホルダーテキストを生成。段落、単語、文の数を指定可能。デザインモックアップやプロトタイピングに。"},checksum:{title:"ファイルチェックサム計算ツール",description:"ファイルやテキストのチェックサムを計算して整合性を検証。CRC32、MD5、SHA1、SHA256、SHA384、SHA512に対応。ダウンロードやバックアップに。"},"inspector-case-converter":{title:"テキストインスペクター・大文字小文字変換ツール",description:"単語数や文字頻度などのテキスト統計を分析しながら、camelCase、snake_case、PascalCaseなどの間で変換。クリーンなコードのために。"},regex:{title:"正規表現テスター・デバッガー",description:"正規表現をライブマッチング、置換、構文ハイライト付きでテスト・デバッグ。フラグとキャプチャグループに対応し、正確なパターン検証が可能。"},"text-diff":{title:"テキスト差分チェッカー・比較ツール",description:"2つのテキストを並列またはインラインで色分け比較。コード、設定、ログ、ドキュメントの変更を単語・文字レベルの精度で発見。"},"multi-language-translator":{title:"多言語 JSON 翻訳ツール",description:"単語やフレーズを11以上の言語に即座に翻訳。アプリ用（i18n）のcommon.jsonファイルをcamelCase、snake_caseなど任意の形式で生成。"},"markdown-editor":{title:"ライブ Markdown エディター・プレビューア",description:"Markdownをリアルタイムで執筆・編集・プレビュー。構文ハイライト、ライブレンダリング、ダーク/ライトモード、エクスポートオプション対応。メモ、README、ドキュメント、ブログ記事に最適。"},"icon-generator":{title:"iOS・Android 向け AI アプリアイコンジェネレーター",description:"1枚のソース画像からiOS・Android用の完全なアプリアイコンセットを生成。AIによる背景除去で透過アイコン作成、回転・反転ツール、モダンなスタイルテンプレート（角丸、スクワークル、円形）、URLやクリップボードからのアップロード、単一PNG/JPEG出力用カスタムスケール、JPEG背景色の選択、高品質なリサイズと圧縮。"},"image-converter":{title:"画像最適化・変換・PDF 作成ツール",description:"最新フォーマット対応の高度な画像コンバーター：AVIF、WebP、JPEG XL（JXL）、MozJPEG、PNG、アニメーションGIF。品質、リサイズ、最適化、一括処理、フォーマット間変換、複数画像の単一PDF結合（PNG、JPG/JPEG、GIF、WebPのみ）を完全制御。"},"pdf-to-images":{title:"PDF から画像への変換ツール",description:"PDFファイルからページごとに高品質な画像を抽出。PNG/JPEG出力の選択、解像度（72〜288 DPI）とJPEG品質の調整、複数PDFの一括処理、ページプレビュー、個別またはZIPでのダウンロードに対応。"},"ip-geolocation":{title:"IP アドレス地理位置情報の検索",description:"任意のIPアドレス（または現在のIP）の位置情報を即座に取得。都市、地域、国、タイムゾーン、ISP、緯度/経度などを含む。結果は複数形式（JSON、XML、YAMLなど）でエクスポート可能。"}},pt:{"token-generator":{title:"Gerador de Tokens Aleatórios Seguros",description:"Gere tokens aleatórios criptograficamente seguros com comprimento personalizável (1–512 caracteres) e conjuntos de caracteres (maiúsculas, minúsculas, números, símbolos). Ideal para chaves de API, IDs de sessão, palavras-passe ou qualquer necessidade de tokens seguros."},"hash-text":{title:"Gerador de Hash de Texto",description:"Gere hashes seguros a partir de texto ou ficheiros usando os algoritmos MD5, SHA1, SHA256, SHA224, SHA512, SHA384, SHA3 e RIPEMD160. Ideal para verificações de integridade de dados e hashing de palavras-passe."},bcrypt:{title:"Gerador de Hash de Palavra-passe bcrypt",description:"Gere hashes Bcrypt seguros para palavras-passe com fator de custo ajustável. Perfeito para o armazenamento seguro de palavras-passe em aplicações."},"uuids-generator":{title:"Gerador de UUID",description:"Gere UUIDs de todas as versões: NIL (todos zeros), v1 (baseado no tempo), v3 (baseado em nome com MD5), v4 (aleatório), v5 (baseado em nome com SHA-1). Suporta geração em massa (até 50) e namespaces personalizados para v3/v5."},"ulid-generator":{title:"Gerador de ULID",description:"Gere Identificadores Universalmente Únicos e Lexicograficamente Ordenáveis (ULID). Uma alternativa aos UUIDs que é monotónica, ordenável por tempo e segura para URL."},"encrypt-decrypt-text":{title:"Ferramenta de Encriptação e Desencriptação de Texto",description:"Encripte e desencripte texto usando algoritmos simétricos (AES, etc.) com chaves e modos personalizados. Processamento seguro do lado do cliente."},"bip39-passphrase-generator":{title:"Gerador de Frase Mnemónica BIP39",description:"Gere frases mnemónicas BIP39 seguras (12–24 palavras) para carteiras de criptomoedas com força de entropia selecionável."},"hmac-generator":{title:"Gerador de HMAC",description:"Calcule HMAC (código de autenticação de mensagens baseado em hash) usando vários algoritmos de hash e chaves secretas para integridade e autenticação de mensagens."},"rsa-key-pair-generator":{title:"Gerador de Par de Chaves RSA",description:"Gere pares de chaves RSA públicas/privadas com comprimento de bits selecionável (2048, 4096, etc.) para encriptação, assinatura e SSH."},"password-strength-analyzer":{title:"Analisador da Força de Palavras-passe",description:"Analise a força de palavras-passe em tempo real: entropia, tempo estimado de quebra, deteção de padrões comuns e verificações de fugas de dados."},"qr-code":{title:"Gerador de QR Code para URLs e Texto",description:"Crie códigos QR personalizáveis a partir de URLs, texto, emails ou vCards. Transfira em vários formatos com correção de erros e sobreposição de logótipos."},"wifi-qr-code":{title:"Gerador de QR Code para WiFi",description:"Gere códigos QR digitalizáveis para redes WiFi. Suporta WPA/WPA2, WEP, sem palavra-passe, SSIDs ocultos e configurações empresariais WPA2-EAP, com cores personalizadas e transferência instantânea."},barcode:{title:"Gerador de Código de Barras",description:"Gere códigos de barras personalizáveis em vários formatos (CODE128, EAN13, UPC, CODE39 e mais). Ajuste a largura das barras, a altura, as cores, as margens, a posição do texto, o tipo de letra e o estilo. Pré-visualização em tempo real com cópia para a área de transferência e transferência em PNG."},"contact-qr-code":{title:"Gerador de QR Code de Contacto vCard",description:"Gere códigos QR profissionais com a sua informação de contacto completa (formato vCard). Inclua nome, telefone, email, cargo, website, morada e mais. Perfeito para cartões de visita, networking e partilha digital."},"qr-code-reader":{title:"Leitor / Descodificador de QR e Código de Barras",description:"Leia e descodifique códigos QR e códigos de barras 1D/2D instantaneamente a partir de imagens, ficheiros carregados ou da sua webcam. Extraia URLs, texto, informações de contacto, credenciais Wi-Fi, informações de produtos e mais, com resultados em tempo real."},"json-yaml":{title:"Conversor de JSON para YAML Online",description:"Converta facilmente JSON para YAML e YAML para JSON com validação e formatação instantâneas. Perfeito para programadores que trabalham com ficheiros de configuração e troca de dados."},"date-time":{title:"Conversor de Formato de Data e Hora",description:"Transforme datas e timestamps entre vários formatos, incluindo timestamps Unix, strings ISO e padrões personalizados. Ideal para depuração e integrações de API."},"number-base":{title:"Conversor de Base Numérica",description:"Converta rapidamente números entre as bases binária, hexadecimal, decimal e octal. Suporta números grandes e cálculos em tempo real para programadores e engenheiros."},"cron-parser":{title:"Analisador de Expressões cron",description:"Analise expressões cron e transforme-as em descrições claras e legíveis. Suporta segundos, macros (@daily, @hourly, etc.), modo detalhado, formato de 24 horas e explicações detalhadas dos símbolos para agendamento de tarefas."},html:{title:"Codificador e Descodificador de Entidades HTML",description:"Codifique ou descodifique caracteres especiais em entidades HTML para prevenir vulnerabilidades XSS ou apresentar texto formatado de forma segura em conteúdo web."},url:{title:"Codificador e Descodificador de URL",description:"Codifique URLs com percent-encoding para transmissão segura ou descodifique-os de volta para texto legível. Essencial para desenvolvimento web e tratamento de parâmetros de API."},base64:{title:"Codificador e Descodificador de Base64 Online",description:"Codifique dados binários ou texto em Base64 para anexos de email e APIs, ou descodifique-os facilmente com validação integrada."},jwt:{title:"Descodificador e Inspetor de Tokens JWT",description:"Descodifique JSON Web Tokens para inspecionar cabeçalhos, payloads e assinaturas sem chaves secretas. Ótimo para depurar fluxos de autenticação."},json:{title:"Formatador e Validador de JSON",description:"Embeleze, minifique e valide dados JSON em tempo real. Detete erros e garanta que o seu JSON está sintaticamente correto para uma integração sem problemas."},xml:{title:"Formatador e Embelezador de XML",description:"Formate documentos XML para melhor legibilidade, recolha elementos aninhados e valide a estrutura. Útil para configuração XML e troca de dados."},sql:{title:"Formatador e Embelezador de SQL",description:"Formate, embeleze e indente consultas SQL para melhor legibilidade. Suporta sintaxe SQL padrão com indentação personalizável, palavras-chave em maiúsculas e quebras de linha."},"lorem-ipsum":{title:"Gerador de Texto Lorem ipsum",description:"Produza texto de preenchimento personalizável em latim ou noutros idiomas. Especifique parágrafos, palavras ou frases para maquetes de design e prototipagem."},checksum:{title:"Calculadora de Checksum de Ficheiros",description:"Calcule somas de verificação de ficheiros ou texto para verificar a integridade. Suporta CRC32, MD5, SHA1, SHA256, SHA384 e SHA512 para transferências e cópias de segurança."},"inspector-case-converter":{title:"Ferramenta de Inspeção de Texto e Conversão de Maiúsculas/Minúsculas",description:"Analise estatísticas de texto, como contagem de palavras e frequência de caracteres, e converta entre camelCase, snake_case, PascalCase e mais, para um código limpo."},regex:{title:"Testador e Depurador de Expressões Regulares",description:"Teste e depure expressões regulares com correspondência em tempo real, substituição e destaque de sintaxe. Suporta flags e grupos de captura para validação precisa de padrões."},"text-diff":{title:"Verificador e Comparador de Diferenças de Texto",description:"Compare dois textos lado a lado ou em linha com diferenças codificadas por cores. Perfeito para identificar alterações em código, configurações, registos ou documentos com precisão ao nível da palavra e do carácter."},"multi-language-translator":{title:"Tradutor de JSON Multilíngue",description:"Traduza palavras e frases para mais de 11 idiomas instantaneamente. Gere ficheiros common.json prontos a usar para a sua aplicação (i18n) com camelCase, snake_case ou qualquer outro formato."},"markdown-editor":{title:"Editor e Pré-visualizador de Markdown ao Vivo",description:"Escreva, edite e pré-visualize Markdown em tempo real com destaque de sintaxe, renderização ao vivo, suporte de modo escuro/claro e opções de exportação. Perfeito para notas, READMEs, documentação e artigos de blog."},"icon-generator":{title:"Gerador de Ícones de Aplicações com IA para iOS e Android",description:"Gere conjuntos completos de ícones de aplicação para iOS e Android a partir de uma única imagem de origem. Remoção de fundo com IA para ícones transparentes, ferramentas de rotação e espelhamento, modelos de estilo modernos (Rounded, Squircle, Circle), carregamento por URL ou colagem da área de transferência, escalas personalizadas para exportações individuais em PNG/JPEG, cor de fundo selecionável para JPEG, redimensionamento e compressão de alta qualidade."},"image-converter":{title:"Otimizador, Conversor de Imagens e Criador de PDF",description:"Conversor de imagens avançado com suporte para formatos modernos: AVIF, WebP, JPEG XL (JXL), MozJPEG, PNG e GIF animado. Controlo total sobre qualidade, redimensionamento, otimização, processamento em lote, conversão entre formatos e combinação de imagens num único PDF (apenas PNG, JPG/JPEG, GIF, WebP)."},"pdf-to-images":{title:"Conversor de PDF para Imagens",description:"Extraia imagens de alta qualidade de ficheiros PDF, página a página. Escolha a saída em PNG ou JPEG, ajuste a resolução (72–288 DPI) e a qualidade JPEG, processe vários PDF em lote, pré-visualize páginas e transfira individualmente ou como ZIP."},"ip-geolocation":{title:"Localização Geográfica de Endereço IP",description:"Obtenha instantaneamente dados de geolocalização de qualquer endereço IP (ou do seu IP atual). Inclui cidade, região, país, fuso horário, ISP, latitude/longitude e mais. Resultados exportáveis em vários formatos (JSON, XML, YAML, etc.)."}},ru:{"token-generator":{title:"Генератор безопасных случайных токенов",description:"Генерируйте криптографически стойкие случайные токены с настраиваемой длиной (1–512 символов) и наборами символов (заглавные, строчные, цифры, символы). Идеально для API-ключей, идентификаторов сессий, паролей и любых задач, требующих безопасных токенов."},"hash-text":{title:"Генератор хешей текста",description:"Генерируйте безопасные хеши из текста или файлов с помощью алгоритмов MD5, SHA1, SHA256, SHA224, SHA512, SHA384, SHA3 и RIPEMD160. Идеально для проверки целостности данных и хеширования паролей."},bcrypt:{title:"Генератор хешей паролей bcrypt",description:"Генерируйте безопасные хеши Bcrypt для паролей с настраиваемым фактором стоимости. Отлично подходит для безопасного хранения паролей в приложениях."},"uuids-generator":{title:"Генератор UUID",description:"Генерируйте UUID всех версий: NIL (все нули), v1 (на основе времени), v3 (на основе имени, MD5), v4 (случайный), v5 (на основе имени, SHA-1). Поддерживается массовая генерация (до 50) и пользовательские пространства имён для v3/v5."},"ulid-generator":{title:"Генератор ULID",description:"Генерируйте универсальные уникальные лексикографически сортируемые идентификаторы (ULID). Монотонная, сортируемая по времени и безопасная для URL альтернатива UUID."},"encrypt-decrypt-text":{title:"Инструмент шифрования и расшифровки текста",description:"Шифруйте и расшифровывайте текст с помощью симметричных алгоритмов (AES и др.) с пользовательскими ключами и режимами. Безопасная обработка на стороне клиента."},"bip39-passphrase-generator":{title:"Генератор мнемонических фраз BIP39",description:"Генерируйте безопасные мнемонические фразы BIP39 (12–24 слова) для криптовалютных кошельков с выбираемой стойкостью энтропии."},"hmac-generator":{title:"Генератор HMAC",description:"Вычисляйте HMAC (код аутентификации сообщений на основе хеша) с использованием различных алгоритмов хеширования и секретных ключей для целостности и аутентификации сообщений."},"rsa-key-pair-generator":{title:"Генератор пар ключей RSA",description:"Генерируйте пары открытых/закрытых ключей RSA с выбираемой длиной в битах (2048, 4096 и т. д.) для шифрования, подписей и SSH."},"password-strength-analyzer":{title:"Анализатор надёжности паролей",description:"Анализируйте надёжность паролей в реальном времени: энтропия, оценка времени взлома, обнаружение распространённых шаблонов и проверка утечек."},"qr-code":{title:"Генератор QR-кодов для ссылок и текста",description:"Создавайте настраиваемые QR-коды из URL, текста, email или vCard. Скачивайте в нескольких форматах с коррекцией ошибок и наложением логотипов."},"wifi-qr-code":{title:"Генератор QR-кодов Wi-Fi",description:"Генерируйте сканируемые QR-коды для сетей WiFi. Поддержка WPA/WPA2, WEP, сетей без пароля, скрытых SSID и корпоративных конфигураций WPA2-EAP с пользовательскими цветами и мгновенным скачиванием."},barcode:{title:"Генератор штрихкодов",description:"Генерируйте настраиваемые штрихкоды в различных форматах (CODE128, EAN13, UPC, CODE39 и др.). Настраивайте ширину штрихов, высоту, цвета, отступы, положение текста, шрифт и оформление. Предпросмотр в реальном времени с копированием в буфер обмена и скачиванием PNG."},"contact-qr-code":{title:"Генератор QR-кодов контактов vCard",description:"Генерируйте профессиональные QR-коды с полной контактной информацией (формат vCard). Включайте имя, телефон, email, должность, веб-сайт, адрес и многое другое. Идеально для визиток, нетворкинга и цифрового обмена."},"qr-code-reader":{title:"Сканер и декодер QR-кодов и штрихкодов",description:"Сканируйте и декодируйте QR-коды и 1D/2D штрихкоды мгновенно из изображений, загруженных файлов или веб-камеры. Извлекайте URL, текст, контактные данные, учётные данные Wi-Fi, информацию о продуктах и многое другое с результатами в реальном времени."},"json-yaml":{title:"Онлайн-конвертер JSON в YAML",description:"Легко конвертируйте JSON в YAML и YAML в JSON с мгновенной валидацией и форматированием. Идеально для разработчиков, работающих с конфигурационными файлами и обменом данными."},"date-time":{title:"Конвертер форматов даты и времени",description:"Преобразуйте даты и метки времени между различными форматами, включая Unix-время, ISO-строки и пользовательские шаблоны. Идеально для отладки и интеграции с API."},"number-base":{title:"Конвертер систем счисления",description:"Быстро конвертируйте числа между двоичной, шестнадцатеричной, десятичной и восьмеричной системами счисления. Поддержка больших чисел и вычислений в реальном времени для программистов и инженеров."},"cron-parser":{title:"Парсер выражений cron",description:"Разбирайте cron-выражения в понятные, человекочитаемые описания. Поддержка секунд, макросов (@daily, @hourly и др.), подробного режима, 24-часового формата и детальных объяснений символов для планирования задач."},html:{title:"Кодировщик и декодировщик HTML-сущностей",description:"Кодируйте и декодируйте специальные символы в HTML-сущности для предотвращения XSS-уязвимостей или безопасного отображения форматированного текста в веб-контенте."},url:{title:"Кодировщик и декодировщик URL",description:"Кодируйте URL с помощью процентного кодирования для безопасной передачи или декодируйте их обратно в читаемый текст. Незаменимо для веб-разработки и работы с параметрами API."},base64:{title:"Онлайн-кодировщик и декодировщик Base64",description:"Кодируйте бинарные данные или текст в Base64 для почтовых вложений и API или легко декодируйте обратно со встроенной валидацией."},jwt:{title:"Декодер и инспектор токенов JWT",description:"Декодируйте токены JSON Web Token для просмотра заголовков, полезной нагрузки и подписей без секретных ключей. Отлично подходит для отладки потоков аутентификации."},json:{title:"Форматтер и валидатор JSON",description:"Форматируйте, минифицируйте и валидируйте данные JSON в реальном времени. Обнаруживайте ошибки и убедитесь, что ваш JSON синтаксически корректен для бесшовной интеграции."},xml:{title:"Форматтер и красивый вывод XML",description:"Форматируйте XML-документы для удобочитаемости, сворачивайте вложенные элементы и проверяйте структуру. Полезно для конфигураций XML и обмена данными."},sql:{title:"Форматтер и оформитель SQL",description:"Форматируйте и структурируйте SQL-запросы для улучшения читаемости. Поддержка стандартного синтаксиса SQL с настраиваемыми отступами, ключевыми словами в верхнем регистре и переносами строк."},"lorem-ipsum":{title:"Генератор текста Lorem Ipsum",description:"Создавайте настраиваемый текст-заполнитель на латыни или других языках. Задавайте количество абзацев, слов или предложений для макетов и прототипов."},checksum:{title:"Калькулятор контрольных сумм файлов",description:"Вычисляйте контрольные суммы файлов или текста для проверки целостности. Поддержка CRC32, MD5, SHA1, SHA256, SHA384 и SHA512 для загрузок и резервных копий."},"inspector-case-converter":{title:"Инспектор текста и конвертер регистра",description:"Анализируйте статистику текста, такую как количество слов и частота символов, и конвертируйте между camelCase, snake_case, PascalCase и другими стилями для чистого кода."},regex:{title:"Тестер и отладчик регулярных выражений",description:"Тестируйте и отлаживайте регулярные выражения с живым сопоставлением, заменой и подсветкой синтаксиса. Поддержка флагов и групп захвата для точной проверки шаблонов."},"text-diff":{title:"Проверка и сравнение различий текста",description:"Сравнивайте два текста рядом или встроенно с цветовой подсветкой различий. Идеально для выявления изменений в коде, конфигурациях, логах или документах с точностью до слов и символов."},"multi-language-translator":{title:"Многоязычный переводчик JSON",description:"Мгновенно переводите слова и фразы на 11+ языков. Генерируйте готовые файлы common.json для вашего приложения (i18n) в camelCase, snake_case или любом другом формате."},"markdown-editor":{title:"Редактор Markdown с предпросмотром в реальном времени",description:"Пишите, редактируйте и просматривайте Markdown в реальном времени с подсветкой синтаксиса, живым рендерингом, поддержкой тёмной/светлой темы и опциями экспорта. Идеально для заметок, README, документации и постов в блоге."},"icon-generator":{title:"ИИ-генератор иконок приложений для iOS и Android",description:"Генерируйте полные наборы иконок приложений для iOS и Android из одного исходного изображения. Удаление фона с помощью ИИ для прозрачных иконок, инструменты поворота и отражения, современные шаблоны стилей (Rounded, Squircle, Circle), загрузка по URL или вставка из буфера обмена, пользовательские масштабы для экспорта одиночных PNG/JPEG, выбор цвета фона для JPEG, высококачественное масштабирование и сжатие."},"image-converter":{title:"Оптимизатор и конвертер изображений с созданием PDF",description:"Продвинутый конвертер изображений с поддержкой современных форматов: AVIF, WebP, JPEG XL (JXL), MozJPEG, PNG и анимированный GIF. Полный контроль над качеством, изменением размера, оптимизацией, пакетной обработкой, конвертацией между форматами и объединением изображений в один PDF (только PNG, JPG/JPEG, GIF, WebP)."},"pdf-to-images":{title:"Конвертер PDF в изображения",description:"Извлекайте высококачественные изображения из PDF-файлов постранично. Выбирайте вывод в PNG или JPEG, настраивайте разрешение (72–288 DPI), качество JPEG, обрабатывайте несколько PDF пакетно, просматривайте страницы и скачивайте по отдельности или в виде ZIP."},"ip-geolocation":{title:"Определение геолокации по IP-адресу",description:"Мгновенно получайте данные геолокации для любого IP-адреса (или вашего текущего IP). Включает город, регион, страну, часовой пояс, ISP, широту/долготу и многое другое. Результаты экспортируются в нескольких форматах (JSON, XML, YAML и др.)."}},vi:{"token-generator":{title:"Trình tạo Token ngẫu nhiên an toàn",description:"Tạo token ngẫu nhiên an toàn mật mã với độ dài tùy chỉnh (1–512 ký tự) và bộ ký tự (chữ hoa, chữ thường, số, ký hiệu). Lý tưởng cho API key, session ID, mật khẩu hoặc mọi nhu cầu token bảo mật."},"hash-text":{title:"Trình tạo mã Hash văn bản",description:"Tạo hash an toàn từ văn bản hoặc tệp bằng các thuật toán MD5, SHA1, SHA256, SHA224, SHA512, SHA384, SHA3 và RIPEMD160. Lý tưởng cho kiểm tra tính toàn vẹn dữ liệu và băm mật khẩu."},bcrypt:{title:"Trình tạo mã băm mật khẩu Bcrypt",description:"Tạo hash Bcrypt an toàn cho mật khẩu với hệ số chi phí điều chỉnh được. Hoàn hảo cho việc lưu trữ mật khẩu an toàn trong ứng dụng."},"uuids-generator":{title:"Trình tạo UUID",description:"Tạo UUID mọi phiên bản: NIL (toàn số 0), v1 (theo thời gian), v3 (theo tên MD5), v4 (ngẫu nhiên), v5 (theo tên SHA-1). Hỗ trợ tạo hàng loạt (tối đa 50), namespace tùy chỉnh cho v3/v5."},"ulid-generator":{title:"Trình tạo ULID",description:"Tạo ULID (định danh duy nhất toàn cầu sắp xếp được theo thứ tự từ điển). Thay thế UUID với tính đơn điệu, sắp xếp theo thời gian và an toàn cho URL."},"encrypt-decrypt-text":{title:"Công cụ mã hóa & giải mã văn bản",description:"Mã hóa và giải mã văn bản bằng thuật toán đối xứng (AES, v.v.) với khóa và chế độ tùy chỉnh. Xử lý an toàn phía trình duyệt."},"bip39-passphrase-generator":{title:"Trình tạo cụm từ ghi nhớ BIP39",description:"Tạo cụm từ ghi nhớ BIP39 an toàn (12–24 từ) cho ví tiền mã hóa với độ mạnh entropy tùy chọn."},"hmac-generator":{title:"Trình tạo HMAC",description:"Tính HMAC (mã xác thực thông điệp dựa trên hash) bằng nhiều thuật toán hash và khóa bí mật để đảm bảo tính toàn vẹn và xác thực thông điệp."},"rsa-key-pair-generator":{title:"Trình tạo cặp khóa RSA",description:"Tạo cặp khóa RSA công khai/riêng tư với độ dài bit tùy chọn (2048, 4096, v.v.) cho mã hóa, ký số và SSH."},"password-strength-analyzer":{title:"Công cụ phân tích độ mạnh mật khẩu",description:"Phân tích độ mạnh mật khẩu theo thời gian thực: entropy, ước tính thời gian bẻ khóa, phát hiện mẫu phổ biến và kiểm tra rò rỉ."},"qr-code":{title:"Trình tạo mã QR cho URL và văn bản",description:"Tạo mã QR tùy chỉnh từ URL, văn bản, email hoặc vCard. Tải xuống nhiều định dạng với sửa lỗi và chèn logo."},"wifi-qr-code":{title:"Trình tạo mã QR WiFi",description:"Tạo mã QR quét được cho mạng WiFi. Hỗ trợ WPA/WPA2, WEP, không mật khẩu, SSID ẩn và cấu hình doanh nghiệp WPA2-EAP với màu tùy chỉnh và tải xuống ngay."},barcode:{title:"Trình tạo mã vạch",description:"Tạo mã vạch tùy chỉnh với nhiều định dạng (CODE128, EAN13, UPC, CODE39, v.v.). Điều chỉnh độ rộng vạch, chiều cao, màu sắc, lề, vị trí chữ, phông và kiểu dáng. Xem trước thời gian thực, sao chép vào clipboard và tải PNG."},"contact-qr-code":{title:"Trình tạo mã QR danh thiếp vCard",description:"Tạo mã QR chuyên nghiệp chứa đầy đủ thông tin liên hệ của bạn (định dạng vCard). Bao gồm tên, điện thoại, email, chức danh, website, địa chỉ và hơn thế nữa. Hoàn hảo cho danh thiếp, kết nối và chia sẻ số."},"qr-code-reader":{title:"Trình đọc / giải mã QR & mã vạch",description:"Quét và giải mã mã QR cùng mã vạch 1D/2D ngay lập tức từ hình ảnh, tệp tải lên hoặc webcam. Trích xuất URL, văn bản, thông tin liên hệ, thông tin Wi-Fi, thông tin sản phẩm và hơn nữa với kết quả thời gian thực."},"json-yaml":{title:"Trình chuyển đổi JSON sang YAML trực tuyến",description:"Chuyển đổi liền mạch JSON sang YAML và ngược lại với xác thực và định dạng tức thì. Hoàn hảo cho lập trình viên xử lý tệp cấu hình và trao đổi dữ liệu."},"date-time":{title:"Trình chuyển đổi định dạng ngày giờ",description:"Chuyển đổi ngày giờ và timestamp giữa nhiều định dạng, gồm Unix timestamp, chuỗi ISO và mẫu tùy chỉnh. Lý tưởng cho gỡ lỗi và tích hợp API."},"number-base":{title:"Trình chuyển đổi hệ cơ số",description:"Chuyển đổi nhanh số giữa hệ nhị phân, thập lục phân, thập phân và bát phân. Hỗ trợ số lớn và tính toán thời gian thực cho lập trình viên và kỹ sư."},"cron-parser":{title:"Trình phân tích biểu thức Cron",description:"Phân tích biểu thức cron thành mô tả rõ ràng, dễ hiểu. Hỗ trợ giây, macro (@daily, @hourly, v.v.), chế độ chi tiết, định dạng 24 giờ và giải thích ký hiệu chi tiết cho lập lịch tác vụ."},html:{title:"Trình mã hóa và giải mã thực thể HTML",description:"Mã hóa hoặc giải mã ký tự đặc biệt thành thực thể HTML để ngăn lỗ hổng XSS hoặc hiển thị văn bản định dạng an toàn trong nội dung web."},url:{title:"Trình mã hóa và giải mã URL",description:"Mã hóa URL bằng percent-encoding để truyền an toàn hoặc giải mã về văn bản dễ đọc. Thiết yếu cho phát triển web và xử lý tham số API."},base64:{title:"Trình mã hóa và giải mã Base64 trực tuyến",description:"Mã hóa dữ liệu nhị phân hoặc văn bản sang Base64 cho tệp đính kèm email và API, hoặc giải mã dễ dàng với xác thực tích hợp."},jwt:{title:"Trình giải mã và kiểm tra JWT Token",description:"Giải mã JSON Web Token để xem header, payload và chữ ký mà không cần khóa bí mật. Tuyệt vời cho gỡ lỗi luồng xác thực."},json:{title:"Trình định dạng và kiểm tra JSON",description:"Làm đẹp, nén và xác thực dữ liệu JSON theo thời gian thực. Phát hiện lỗi và đảm bảo JSON đúng cú pháp để tích hợp liền mạch."},xml:{title:"Trình định dạng và làm đẹp XML",description:"Định dạng tài liệu XML cho dễ đọc, thu gọn phần tử lồng nhau và xác thực cấu trúc. Hữu ích cho cấu hình XML và trao đổi dữ liệu."},sql:{title:"Trình định dạng và làm đẹp SQL",description:"Định dạng, làm đẹp và thụt lề truy vấn SQL để dễ đọc hơn. Hỗ trợ cú pháp SQL chuẩn với thụt lề tùy chỉnh, từ khóa viết hoa và ngắt dòng."},"lorem-ipsum":{title:"Trình tạo văn bản Lorem Ipsum",description:"Tạo văn bản giữ chỗ tùy chỉnh bằng tiếng Latin hoặc ngôn ngữ khác. Chỉ định số đoạn, từ hoặc câu cho bản mẫu thiết kế và tạo mẫu."},checksum:{title:"Công cụ tính Checksum tệp",description:"Tính checksum cho tệp hoặc văn bản để xác minh tính toàn vẹn. Hỗ trợ CRC32, MD5, SHA1, SHA256, SHA384 và SHA512 cho tải xuống và sao lưu."},"inspector-case-converter":{title:"Công cụ kiểm tra văn bản và chuyển đổi kiểu chữ",description:"Phân tích thống kê văn bản như số từ và tần suất ký tự, đồng thời chuyển đổi giữa camelCase, snake_case, PascalCase và nhiều kiểu khác cho mã sạch."},regex:{title:"Công cụ kiểm tra và gỡ lỗi biểu thức chính quy",description:"Kiểm tra và gỡ lỗi biểu thức chính quy với khớp trực tiếp, thay thế và tô sáng cú pháp. Hỗ trợ cờ và nhóm bắt để xác thực mẫu chính xác."},"text-diff":{title:"Công cụ so sánh và đối chiếu văn bản",description:"So sánh hai đoạn văn bản song song hoặc nội dòng với khác biệt được tô màu. Hoàn hảo để phát hiện thay đổi trong mã, cấu hình, log hoặc tài liệu với độ chính xác đến từng từ và ký tự."},"multi-language-translator":{title:"Trình dịch JSON đa ngôn ngữ",description:"Dịch từ và cụm từ sang hơn 11 ngôn ngữ ngay lập tức. Tạo tệp common.json sẵn dùng cho ứng dụng (i18n) với camelCase, snake_case hoặc bất kỳ định dạng nào."},"markdown-editor":{title:"Trình soạn thảo & xem trước Markdown trực tiếp",description:"Viết, chỉnh sửa và xem trước Markdown theo thời gian thực với tô sáng cú pháp, kết xuất trực tiếp, hỗ trợ chế độ sáng/tối và tùy chọn xuất. Hoàn hảo cho ghi chú, README, tài liệu và bài blog."},"icon-generator":{title:"Trình tạo icon ứng dụng AI cho iOS & Android",description:"Tạo bộ icon ứng dụng đầy đủ cho iOS và Android từ một ảnh nguồn. Xóa nền bằng AI cho icon trong suốt, công cụ xoay & lật, mẫu kiểu hiện đại (Bo tròn, Squircle, Tròn), tải lên từ URL hoặc dán từ clipboard, tỷ lệ tùy chỉnh khi xuất PNG/JPEG đơn, chọn màu nền cho JPEG, thay đổi kích thước & nén chất lượng cao."},"image-converter":{title:"Trình tối ưu, chuyển đổi ảnh và tạo PDF",description:"Trình chuyển đổi ảnh nâng cao hỗ trợ định dạng hiện đại: AVIF, WebP, JPEG XL (JXL), MozJPEG, PNG và GIF động. Kiểm soát hoàn toàn chất lượng, thay đổi kích thước, tối ưu hóa, xử lý hàng loạt, chuyển đổi giữa các định dạng và ghép ảnh thành một tệp PDF (chỉ PNG, JPG/JPEG, GIF, WebP)."},"pdf-to-images":{title:"Trình chuyển đổi PDF sang ảnh",description:"Trích xuất ảnh chất lượng cao từ tệp PDF theo từng trang. Chọn đầu ra PNG hoặc JPEG, điều chỉnh độ phân giải (72–288 DPI), chất lượng JPEG, xử lý hàng loạt nhiều PDF, xem trước trang và tải xuống riêng lẻ hoặc dạng ZIP."},"ip-geolocation":{title:"Tra cứu vị trí địa lý địa chỉ IP",description:"Truy xuất ngay dữ liệu vị trí địa lý của bất kỳ địa chỉ IP nào (hoặc IP hiện tại của bạn). Bao gồm thành phố, vùng, quốc gia, múi giờ, ISP, vĩ độ/kinh độ và hơn nữa. Kết quả xuất được nhiều định dạng (JSON, XML, YAML, v.v.)."}}};e.s(["default",0,function({children:e}){let c,l=(0,r.useRouter)(),p=(0,r.usePathname)(),u=p.split("/")[1]||"en",[m,h]=(0,t.useState)(!1),g=a.allTools.find(e=>`/${u}/tools/${e.slug}/`===p)||null,v=g?.slug||"",S=g?(c=g.slug,d[u]?.[c]??null)?.title??g.longName:"GadgetForge";return(0,i.jsx)(n.ToastProvider,{children:(0,i.jsx)(s.default,{selectedToolTitle:S,currentSlug:v,onToolSelect:e=>{l.replace(`/${u}/tools/${e.slug}/`,{scroll:!1}),h(!1)},children:(0,i.jsx)("div",{className:"flex-grow-1 p-2 pb-5 pb-md-3",children:(0,i.jsx)(o.RightSidebarToolProvider,{children:e})})})})}],115529)}]);